const MOCK_RC = {"t1": {"p5": [{"n": 101, "en": "Rather than restocking products that do not sell well, the store donates ______ to local charities in need.", "opts": ["it", "its", "their", "them"], "ans": 3}, {"n": 102, "en": "______ the city is repairing Sabo Road, please access the parking lot from Hutton Street only.", "opts": ["Later", "While", "As though", "Yet"], "ans": 1}, {"n": 103, "en": "Restaurant patrons can try a sample of the new appetizer ______ created for the summer menu.", "opts": ["ours", "our", "us", "we"], "ans": 3}, {"n": 104, "en": "Unless the event organizer can ______ an alternative venue, the Melody Music Festival may not be held this year.", "opts": ["distribute", "select", "perform", "withdraw"], "ans": 1}, {"n": 105, "en": "Ms. Burton accepted a position at Rendy Tech ______ a senior software programmer.", "opts": ["as", "on", "upon", "about"], "ans": 0}, {"n": 106, "en": "The blender includes ______ blades, so customers should use extreme caution when cleaning it.", "opts": ["sharply", "sharp", "sharpness", "sharpen"], "ans": 1}, {"n": 107, "en": "Ryder Tech has been ______ to developing innovative solutions for supply chain optimization.", "opts": ["finalized", "emerged", "devoted", "tended"], "ans": 2}, {"n": 108, "en": "The details about the new Web site's contents as well as ______ functionality will be withheld until further notice.", "opts": ["it", "its", "they", "them"], "ans": 1}, {"n": 109, "en": "Local business owners predict that the newly opened theme park will ______ economic growth.", "opts": ["contain", "stimulate", "prefer", "negotiate"], "ans": 1}, {"n": 110, "en": "The HR manager cannot personally conduct the numerous in-depth ______ required for the hiring process.", "opts": ["interviewing", "interviewer", "interviews", "interviewed"], "ans": 2}, {"n": 111, "en": "The company excursion to Bali was a great success, ______ the weather was slightly disappointing.", "opts": ["seldom", "though", "rarely", "even"], "ans": 1}, {"n": 112, "en": "Designers hope that the new logo will help consumers ______ recognize the brand.", "opts": ["recently", "partially", "originally", "instantly"], "ans": 3}, {"n": 113, "en": "______ the lack of vegetarian dishes, the menu at Eduardo's Restaurant is very diverse.", "opts": ["Along", "Even if", "Aside from", "Because"], "ans": 2}, {"n": 114, "en": "______ is ordered through our online store by midnight will be shipped within the next 24 hours.", "opts": ["Each", "Whatever", "That", "Neither"], "ans": 1}, {"n": 115, "en": "Wonderworld Theme Park visitors are reminded to ______ from using mobile phones while enjoying the park's rides.", "opts": ["refrain", "forbid", "retreat", "hesitate"], "ans": 0}, {"n": 116, "en": "Televisions sold during Digital Center's grand opening event this weekend ______ an extended 5-year warranty.", "opts": ["includes", "will include", "including", "had included"], "ans": 1}, {"n": 117, "en": "Board members will ______ a new chairperson by secret ballot at the annual meeting in June.", "opts": ["elect", "alleviate", "perceive", "dedicate"], "ans": 0}, {"n": 118, "en": "Taxes and shipping fees will be calculated ______ from the total cost of the goods.", "opts": ["separated", "separation", "separately", "separating"], "ans": 2}, {"n": 119, "en": "To avoid contamination from agricultural goods, the country has ______ regulations regarding imports.", "opts": ["strictest", "strictness", "strictly", "strict"], "ans": 3}, {"n": 120, "en": "Ms. Pullman must keep her work attendance above 93 percent or she will ______ losing her annual bonus.", "opts": ["risk", "protect", "hold", "cancel"], "ans": 0}, {"n": 121, "en": "Working long hours does not ______ contribute to an increase in productivity overall.", "opts": ["necessitate", "necessarily", "necessary", "necessity"], "ans": 1}, {"n": 122, "en": "During the presentation, exhibiting confidence will help to reduce investors' ______ about the project.", "opts": ["settlements", "uncertainties", "preferences", "fluctuations"], "ans": 1}, {"n": 123, "en": "Patrons ______ from bringing their own food or beverages into the movie theater.", "opts": ["prohibit", "are prohibited", "prohibited", "prohibiting"], "ans": 1}, {"n": 124, "en": "To ______ for the sales position, candidates must have at least three years of relevant experience.", "opts": ["enroll", "qualify", "involve", "persuade"], "ans": 1}, {"n": 125, "en": "The ______ of your online account will be completed within 24 hours after your details are verified.", "opts": ["activation", "active", "actively", "activate"], "ans": 0}, {"n": 126, "en": "Real estate agents understand that hosting an open house is a great way to show the property to ______ buyers.", "opts": ["temporary", "unlimited", "potential", "extensive"], "ans": 2}, {"n": 127, "en": "The train stops in ______ cities before reaching its final destination in Berlin at approximately 11 P.M.", "opts": ["multiplied", "multiply", "multiple", "multiplying"], "ans": 2}, {"n": 128, "en": "Visitors to the cathedral can easily ______ five euros by tapping their credit card on the payment terminal.", "opts": ["recharge", "settle", "participate", "donate"], "ans": 3}, {"n": 129, "en": "The current safety procedures at Ewing Manufacturing ______ all industry standards.", "opts": ["satisfactory", "satisfactorily", "satisfy", "satisfaction"], "ans": 2}, {"n": 130, "en": "At the year-end party, Ms. Cohen was ______ with the Employee of the Year award for her exceptional dedication and outstanding performance.", "opts": ["nominated", "evaluated", "honored", "accepted"], "ans": 2}], "p6": [{"title": "Questions 131-134 refer to the following e-mail.", "text": "To: Erin Reynolds <ereynolds@reesecorp.com>\nFrom: Brandon Holcomb <bholcomb@reesecorp.com>\nDate: May 3\nSubject: Parking lot\n\nDear Ms. Reynolds,\n\nI am writing in response to the announcement that the employee parking lot will be partially closed next month for repairs. (131)______.\n\nDuring the partial closure, would it be possible to allocate parking spaces for staff members who carpool? Taking public transportation is not a (132)______ option for a lot of people. So, this (133)______ more people to share rides, reducing the number of vehicles in the lot.\n\nIf you like the idea, I can write a memo explaining the details and how people can participate. Offering the best parking spots, the ones near the entrance, will provide the most (134)______ for forming carpool groups. Please let me know what you think.\n\nSincerely,\n\nBrandon", "qs": [{"n": 131, "opts": ["I apologize for not having made this information public sooner.", "Even so, the noise may be a disruption to the staff.", "The work may be completed earlier than expected.", "Accordingly, I have a suggestion that may be of interest."], "ans": 3}, {"n": 132, "opts": ["grateful", "consecutive", "thorough", "viable"], "ans": 3}, {"n": 133, "opts": ["to encourage", "encouraging", "is encouraged", "would encourage"], "ans": 3}, {"n": 134, "opts": ["motivate", "motivation", "motivational", "motivated"], "ans": 1}]}, {"title": "Questions 135-138 refer to the following article.", "text": "New Facilities for National Park Visitors\n\nRAVENSBROOK (April 21) — Gray Mountains National Park will open a new visitor center this weekend. The center is open from 8 A.M. to 7 P.M. daily. (135)______. For a breakdown of charges, visit www.graymts.org/admission.\n\nThe new center has been built near the entrance, on the area (136)______ used to be a meadow. The building features a rooftop garden, recovering some of the lost space for plants and providing habitats for bees and butterflies. In the center, visitors can enjoy interactive exhibits and purchase maps, supplies, and souvenirs. (137)______, there are restrooms, a small café, and a spacious seating area.\n\nThe grand opening is scheduled for April 26. The first one thousand visitors (138)______ a pin with the park's logo.", "qs": [{"n": 135, "opts": ["We apologize for the temporary closure of this building.", "The national park is home to a wide range of endangered species.", "Use of the facility is included in the park's entry fee.", "The project budget covers the renovation of numerous centers."], "ans": 2}, {"n": 136, "opts": ["what", "such", "that", "when"], "ans": 2}, {"n": 137, "opts": ["Recently", "Conversely", "Therefore", "Furthermore"], "ans": 3}, {"n": 138, "opts": ["were given", "are giving", "will be given", "will have given"], "ans": 2}]}, {"title": "Questions 139-142 refer to the following e-mail.", "text": "To: Undisclosed Recipients\nFrom: Tetrick Electronics <info@tetrickelectronics.com>\nDate: December 8\nSubject: Product Recall: TH-1749\n\nDear Customer,\n\nTetrick Electronics is initiating an immediate recall of our space heater, model TH-1749, due to a critical safety concern. Extensive testing has revealed that the heating element can (139)______ too much heat, resulting in a fire risk. Customers with this model may visit www.tetrickelectronics.com/recall to print a shipping label and mail it back for free. (140)______, customers are welcome to bring the defective product to any of our retail locations, where returns will be processed on the spot, and refunds will be issued immediately upon receipt of the item. (141)______. That's why we are working to reclaim all faulty items despite the high cost and considerable effort. We deeply regret any inconvenience this recall may cause, and we appreciate the ongoing trust and cooperation of our customers while we (142)______ this issue.\n\nThank you for your understanding,\n\nThe Tetrick Electronics Team", "qs": [{"n": 139, "opts": ["pursue", "fulfill", "vary", "generate"], "ans": 3}, {"n": 140, "opts": ["Alternatively", "Consequently", "In fact", "Nevertheless"], "ans": 0}, {"n": 141, "opts": ["Every unit is subject to a thorough inspection process before leaving the factory.", "Due to high demand, your item's delivery date may be subject to delays.", "Our foremost priority is the safety and satisfaction of our customers.", "We are currently developing a new model that includes more advanced heat settings."], "ans": 2}, {"n": 142, "opts": ["have resolved", "resolve", "will resolve", "resolving"], "ans": 1}]}, {"title": "Questions 143-146 refer to the following article.", "text": "The Sinclair Gazette\nDecember 13\n\n(143)______. The museum, which is one of the city's most beloved historical landmarks, has stood on the corner of Markham Road and Drexler Street since its construction in 1934. In all that time, it has barely been modified, and many parts of the building have never changed at all since it was first opened. (144)______, all of the current fixtures and electrical systems are the original ones installed during the initial construction project.\n\nSinclair City Council has made funds available for a large-scale renovation project (145)______ to begin in March. The project will involve the installation of energy-efficient climate control systems, a complete modification of the museum's exterior, and the building of some new exhibit halls and visitor amenities for guests. Work will be completed in time for the museum's grand reopening on May 25th.\n\nLocal residents should expect some noise disruptions and minor traffic delays (146)______ the project is underway, although the city council assures the public that efforts will be made to minimize inconvenience.", "qs": [{"n": 143, "opts": ["Sinclair Metropolitan Museum will be closed down permanently next year.", "The city council has announced plans to relocate Sinclair Metropolitan Museum.", "Sinclair Metropolitan Museum will soon undergo significant remodeling work.", "Employees are required to fill positions at Sinclair Metropolitan Museum."], "ans": 2}, {"n": 144, "opts": ["However", "Recently", "On the other hand", "In fact"], "ans": 3}, {"n": 145, "opts": ["scheduling", "scheduled", "will schedule", "is scheduled"], "ans": 1}, {"n": 146, "opts": ["so that", "during", "once", "following"], "ans": 2}]}], "p7": [{"title": "Questions 147-148 refer to the following e-mail.", "passage": "To: Lois Catrell <loiscatrell@vargomail.com>\nFrom: Scott Garvey <s_garvey@cityviewmovingco.com>\nDate: June 30\nSubject: Cityview Moving Co. Follow-up\n\nDear Ms. Catrell,\n\nThank you for considering Cityview Moving Co. for your forthcoming residential relocation. During our recent telephone conversation, you indicated that your residence comprises a three-bedroom apartment. Based on the dimensions and the inventory you provided, we estimate that the cost of the move will fall within the range of $1,800 to $2,300. As arranged, I will stop by your property tomorrow at 10 A.M. to assess its contents and give you a more accurate custom quote. Regarding the antique furniture pieces that you have, please rest assured that they will be handled by our experienced team with the utmost care. We understand that special items such as these are both expensive and irreplaceable, and we treat them as such.\n\nBest,\n\nScott", "qs": [{"n": 147, "q": "Why will Mr. Garvey visit Ms. Catrell's property?", "opts": ["To pick up some boxes", "To drop off some paperwork", "To prepare an estimate", "To measure some rooms"], "ans": 2}, {"n": 148, "q": "What is suggested about Ms. Catrell?", "opts": ["She has obtained quotes from various businesses.", "She is relocating from one city to another.", "She expressed concern about some valuable items.", "She has used Mr. Garvey's business in the past."], "ans": 2}]}, {"title": "Questions 149-150 refer to the following article.", "passage": "Cybo Opens New Branch\n\nSEATTLE (10 April) — Cybersecurity firm Cybo, known for safeguarding businesses across the country with its innovative detection and prevention of viruses and malware, announced at a press conference yesterday that it will open a new branch in Portland. The company's headquarters will remain at its current location in Seattle, where the entire executive team will continue to operate.\n\nAs part of this strategic expansion, Cybo will relocate its sales and marketing departments to the new branch, along with half of its security analysts and technical consultants. A spokesperson for Cybo also confirmed that additional network engineers will be hired to support the increased demand at both sites. This expansion reflects Cybo's commitment to improving its service capabilities and reaching key markets.", "qs": [{"n": 149, "q": "What does Cybo specialize in?", "opts": ["Developing custom software for businesses", "Protecting businesses from online threats", "Detecting ways in which businesses can save money", "Designing digital advertisements for companies"], "ans": 1}, {"n": 150, "q": "According to the article, what does Cybo intend to do?", "opts": ["Enlarge its sales and marketing teams", "Increase recruitment to meet network demands", "Provide additional training to security analysts", "Enhance and upgrade its range of cyber security products"], "ans": 1}]}, {"title": "Questions 151-152 refer to the following text-message chain.", "passage": "Sophie Lewis [1:25 P.M.]\nI'm working on the gift bags for the Cosmetics Expo. I'm adding a variety of skincare and makeup samples and tying some silver ribbon on the bags as decoration. How soon do you need them?\nNeal Vanburen [1:26 P.M.]\nBy tomorrow at noon. Thanks! Did you put a business card inside each one?\nSophie Lewis [1:27 P.M.]\nI decided to tape them to the outside. I think they'll be more noticeable that way. I can send you some photos.\nNeal Vanburen [1:28 P.M.]\nYou know better than me. I'm sure they already look great. Thanks for all your hard work.\nSophie Lewis [1:30 P.M.]\nMy pleasure. If you need anything else done, just let me know.", "qs": [{"n": 151, "q": "What does Ms. Lewis inquire about?", "opts": ["How to transport items to an expo", "Which colors to use for some decorations", "When a project must be completed", "What to add to some gift bags"], "ans": 2}, {"n": 152, "q": "At 1:28 P.M., what does Mr. Vanburen most likely mean when he writes, “You know better than me”?", "opts": ["He would appreciate seeing Ms. Lewis's images.", "He has confidence in Ms. Lewis's judgement.", "He knows Ms. Lewis will meet a deadline.", "He would like Ms. Lewis to present some gift bags."], "ans": 1}]}, {"title": "Questions 153-155 refer to the following letter.", "passage": "IC Communications\n1805 Lynn Avenue, #106\nAppleton, WI 54915\n\nAugust 27\n\nDaniel Soriano\n922 Veltri Drive\nAppleton, WI 54915\n\nDear Mr. Soriano,\n\nYour one-year service contract with IC Communications is soon coming to an end. Please find below a summary of your current package and the related monthly fees. You requested automatic renewal of your contract, so no further action is needed if you wish to keep the same package. For upgrades or cancellations, which may incur additional charges, contact our customer service team.\n\nPremium high-speed Internet: $95.00\nMobile phone unlimited data and calls: $70.00\nAdditional mobile phone, unlimited data and calls: $40.00\nExtended protection plan (main phone only): $8.00\nWow-Watcher video streaming service: $15.00\n\nMonthly total: $228.00\n\nIf you have any questions, please contact me at 920-555-2045. If I am not available to handle your inquiry, anyone else in the billing department can assist you.\n\nWarmest regards,\n\nGina Rivera\nIC Communications", "qs": [{"n": 153, "q": "What is the purpose of the letter?", "opts": ["To introduce a special promotion for a new Internet package", "To confirm the renewal of a service agreement", "To inform a customer of an upcoming rate increase", "To notify a customer of an error in their billing"], "ans": 1}, {"n": 154, "q": "Who most likely is Ms. Rivera?", "opts": ["A phone repair technician", "A human resources manager", "A billing administrator", "A loan officer"], "ans": 2}, {"n": 155, "q": "According to the letter, what is true about Mr. Soriano?", "opts": ["He has been an IC Communications customer for two years.", "He will receive a new phone with his contract renewal.", "His protection plan only covers one phone.", "He is willing to pay additional charges for upgrades."], "ans": 2}]}, {"title": "Questions 156-157 refer to the following brochure.", "passage": "AQ Tour Company is the top-rated firm for riverboat tours, welcoming thousands of passengers aboard every year. Make your trip memorable with a ride down Vogel River on our beautiful boat, Sunny Voyager. On board, you can enjoy our casual café for lighter bites or something more sophisticated in our fine-dining restaurant, whichever suits your mood. The enormous vessel has an open-air observation deck on top for those who love fresh air and a climate-controlled interior with floor-to-ceiling windows on both sides.\n\nAlong the river, you'll see several chapels, the Alhambra Observatory, Lyon Waterfall, and more. One highlight is the historic Satterfield Manor, which was recently restored by the Midwich Heritage Foundation and is truly an impressive sight to behold. The building is closed to the public and hidden from view from the roadway, but reveals itself to those traveling on our vessel, so do not miss this opportunity to enjoy its 15th century architecture.\n\nVisit www.aqtourco.com to book a departure from Coral Pier or Beacon Harbor. We operate this tour from mid-April to late October.", "qs": [{"n": 156, "q": "What is indicated about Sunny Voyager?", "opts": ["It features two dining establishments.", "It offers a wide variety of onboard activities.", "It embarks on tours from Alhambra Observatory.", "It has recently been upgraded with modern amenities."], "ans": 0}, {"n": 157, "q": "What is suggested about Satterfield Manor?", "opts": ["It was originally used as a chapel.", "It can only be seen from the river.", "It was damaged in the 15th century.", "It is maintained by AQ Tour Company."], "ans": 1}]}, {"title": "Questions 158-160 refer to the following Web page.", "passage": "www.summitrainbarrels.com\n\nHOME | PRODUCT CATALOG | BEGINNERS' INFORMATION | VIDEOS | CONTACT\n\nAre you new to rain barrels?\nHarnessing rainwater in a barrel is not only an environmentally friendly choice but also a practical method to significantly decrease your water consumption. Our Web site features a series of comprehensive tutorial videos designed to guide you through every step of the process, from installation to ongoing maintenance, ensuring your rain barrel operates at maximum efficiency. — [1] —.\n\nGet the benefits!\nSetting up a rain barrel requires only basic tools and a straightforward installation process, making it accessible for nearly everyone. — [2] —. Once your barrel is properly affixed to your home's downspout system, you can effortlessly collect free water every time it rains. The collected rainwater is untreated and free of the harsh chemicals commonly found in tap water, making it ideal for use in your garden. — [3] —. Moreover, the water's temperature naturally adjusts to the surrounding environment, creating optimal conditions for your plants, which may otherwise struggle with colder tap water.\n\nA barrel to suit everyone!\nAt Summit Rain Barrels, we offer an extensive range of sizes and designs, with capacities varying from 100 to 500 liters, ensuring we meet the needs of every household. — [4] —. Wall-mounted barrels provide a space-saving alternative without sacrificing capacity, so they can be a good option. Explore our catalog today to find the perfect rain barrel for your needs!", "qs": [{"n": 158, "q": "What are visitors able to do on the Web site?", "opts": ["Find tips on using less water at home", "Discuss rain barrel issues with other customers", "Watch videos on planting gardens", "Learn about rain barrel installation"], "ans": 3}, {"n": 159, "q": "What is NOT indicated about the water collected by barrels?", "opts": ["It goes through a filtration process.", "It is free from harmful substances.", "Its temperature correlates with the climate.", "It is well-suited for gardening purposes."], "ans": 0}, {"n": 160, "q": "In which of the positions marked [1], [2], [3], and [4] does the following sentence best belong? \"Some properties may have limited ground space.\"", "opts": ["[1]", "[2]", "[3]", "[4]"], "ans": 3}]}, {"title": "Questions 161-163 refer to the following announcement.", "passage": "The Tully Gallery Seeks Art Contest Judges\n\nDo you have a passion for art as well as formal or informal experience in the art world? The Tully Gallery is seeking knowledgeable and discerning individuals to join the judging panel for our prestigious annual art competition.\n\nPrerequisites:\n• A deep engagement with art, either as a practitioner, educator, or dedicated connoisseur\n• Exceptional verbal communication skills for discussing entries with other judges\n• A keen eye for intricacies to recognize subtle elements within assorted artwork\n• Experience in serving as an art contest judge is preferred but not mandatory.\n\nJudges will be expected to attend the following events:\n• May 6: A mandatory training session (9:00 A.M. to 12:00 P.M.) with a complimentary lunch served afterwards at 12:30 P.M. All necessary pens, markers, and notepads will be provided.\n• May 13: Attendance is required at the welcome reception (6:30 P.M.), the assessment and selection round (7:00 P.M.), and the subsequent award ceremony (8:30 P.M.).\n\nHourly compensation will be paid. To express interest in this opportunity, contact Colin Frahm at colin@tullygallery.com.", "qs": [{"n": 161, "q": "According to the announcement, what must applicants have?", "opts": ["Previous judging experience", "Excellent attention to detail", "Strong written communication skills", "A degree in an art-related field"], "ans": 1}, {"n": 162, "q": "What information does the announcement include?", "opts": ["The timeline for hiring decisions", "A deadline for applications", "The dates of required participation", "The hourly wage for judges"], "ans": 2}, {"n": 163, "q": "What is indicated about the training?", "opts": ["Participants will arrive on May 13.", "Participants will be given stationery.", "Participants will receive food during the session.", "Participants will be taught by Colin Frahm."], "ans": 1}]}, {"title": "Questions 164-167 refer to the following article.", "passage": "EASTON, May 12 — At Wednesday's monthly city council meeting, members discussed a number of park improvement projects that will benefit the public. The projects are made possible by a federal grant, which was given to the city last week, and will satisfy increasing demand among local residents for better recreational amenities. The city has applied for such grants many times over the years. — [1] —.\n\n\"Public green spaces are an important component of the well-being of residents,\" city council member Walter Buchanan said. \"It's wonderful to have the opportunity to move forward on projects we've been considering for a long time. — [2] —.\"\n\nUpcoming work will focus solely on Laurel Park. Bleachers for spectators will be built on both sides of the soccer field there, and ramps will be added next to the steps leading to the picnic shelter by the walking path to accommodate those with walking difficulties. These two projects will be carried out by Parks and Recreation employees. — [3] —. There are also plans to build a bridge to connect the small island on Stoney Lake to the shoreline. As this work requires a specialist, the city is currently accepting bids for the work. To submit one, e-mail Elena Ramos at e.ramos@easton.gov.\n\nThe remainder of the funds has not yet been designated. — [4] —. Therefore, residents are invited to attend a meeting on May 31 at the Easton Community Center to share their opinions.", "qs": [{"n": 164, "q": "What did the city of Easton recently do?", "opts": ["It surveyed local residents.", "It elected new city council members.", "It obtained government funds.", "It opened its parks for the season."], "ans": 2}, {"n": 165, "q": "What is NOT indicated as a change that will take place at Laurel Park?", "opts": ["Improving wheelchair accessibility", "Creating access to an island", "Adding seating for a sports field", "Installing more walking paths"], "ans": 3}, {"n": 166, "q": "Why should people e-mail Ms. Ramos?", "opts": ["To report issues with a park", "To make a proposal for a project", "To suggest a new project", "To get a list of city council members"], "ans": 1}, {"n": 167, "q": "In which of the positions marked [1], [2], [3], and [4] does the following sentence best belong? \"After several failed attempts, the efforts of city officials were finally successful.\"", "opts": ["[1]", "[2]", "[3]", "[4]"], "ans": 0}]}, {"title": "Questions 168-171 refer to the following e-mail.", "passage": "E-mail Message\n\nTo: Albert Chaney <a.chaney@topqualityins.com>\nFrom: Heather Phillips <heather@greenscape-services.com>\nDate: April 26\nSubject: GreenScape Services\n\nDear Mr. Chaney,\n\nIt was a pleasure to speak to you on the phone today. I have updated our records. Beginning May 1, we will increase the frequency of lawn mowing at your Hickory Street commercial property to twice a month rather than the current monthly schedule. Accordingly, your monthly payment for lawn mowing will increase to $70.\n\nAdditionally, in the flowerbed, our team will take out the broken statue and replace it with a selection of new plants, including climbing roses. To support the roses, we will install a sturdy frame that complements your garden's style. Please continue to ensure that the gate to this part of the garden is unlocked whenever our team is scheduled to arrive. Our ongoing services will continue to include the weeding of the flowerbeds as needed, ensuring that your garden remains well-maintained throughout the year. Please note that the fee for these services covers the disposal of all garden waste.\n\nWe understand that you have an operation in Bloomington as well. That falls under our service area, and we already have numerous other clients in the region, so we would be happy to provide assistance at that site. Please let me know if this is of interest to you.\n\nRegards,\n\nHeather Phillips\nGreenScape, 309-555-1896", "qs": [{"n": 168, "q": "What is the main purpose of the e-mail?", "opts": ["To promote a newly offered package", "To confirm changes to a service agreement", "To suggest options for some new bushes", "To request payment for landscaping work"], "ans": 1}, {"n": 169, "q": "What is indicated about the flowerbed?", "opts": ["It is surrounded by a wall.", "It has restricted access.", "It will be expanded to a larger size.", "It currently contains several statues."], "ans": 1}, {"n": 170, "q": "The word \"support\" in paragraph 2, line 2, is closest in meaning to", "opts": ["hold up", "encourage", "collaborate", "look after"], "ans": 0}, {"n": 171, "q": "What is suggested about Mr. Chaney?", "opts": ["His company only receives services seasonally.", "He has more than one commercial property.", "He is eligible for a discount on services.", "He referred others to GreenScape."], "ans": 1}]}, {"title": "Questions 172-175 refer to the following online chat discussion.", "passage": "Oscar Ross: Grace, Dominic, do either of you know what's going on with the boxes in the hallway on the second floor? There's a big stack of about seven or eight of them, next to the elevator. [2:17 P.M.]\nGrace Marsden: Those were dropped off by Northbrook Couriers this morning. I don't know who signed for them, but they're addressed to Susan Pearce. I checked to see if there was any label saying what's inside, but there wasn't. [2:19 P.M.]\nOscar Ross: We've got to move them. They're in a high-traffic area. I don't want anyone to trip over them and get hurt, especially a visitor. Do you know why Ms. Pearce hasn't moved them yet? [2:20 P.M.]\nDominic Hawley: She's not in the office this week. She went to Singapore yesterday to discuss the terms of the trade agreement with Pandan Manufacturing. I'm not sure when she'll be back. [2:21 P.M.]\nGrace Marsden: As far as I know, her return flight is scheduled for Friday, and she'll be back in the office on Monday. [2:23 P.M.]\nOscar Ross: Okay, now I see why they've gone untouched, but I don't think we can wait until Monday. Do you have any idea what she wants done with them? [2:26 P.M.]\nDominic Hawley: Mr. Curran works closely with Ms. Pearce. [2:27 P.M.]\nGrace Marsden: Right. He's your best chance. [2:29 P.M.]\nOscar Ross: All right. Thanks! [2:30 P.M.]", "qs": [{"n": 172, "q": "What happened in the morning?", "opts": ["Some items were delivered.", "An elevator started malfunctioning.", "Ms. Pearce left for a business trip.", "Some boxes went missing."], "ans": 0}, {"n": 173, "q": "What is Mr. Ross concerned about?", "opts": ["Getting stuck in traffic", "Causing on-site injuries", "Being late for a trip", "Having too many visitors"], "ans": 2}, {"n": 174, "q": "Why did Ms. Pearce go to Singapore?", "opts": ["To inspect a manufacturing facility", "To address a complaint", "To negotiate a contract", "To participate in a trade fair"], "ans": 2}, {"n": 175, "q": "At 2:27 P.M., what does Mr. Hawley mean when he writes, \"Mr. Curran works closely with Ms. Pearce\"?", "opts": ["Mr. Curran has an office near Ms. Pearce.", "Mr. Curran might know Ms. Pearce's plans.", "Mr. Curran can approve a formal request.", "Mr. Curran will travel with Ms. Pearce."], "ans": 1}]}, {"title": "Questions 176-180 refer to the following information and form.", "passage": "Final Building Inspection — City of Meadowville\n\nTo prepare for a visit from a city building inspector, please ensure that the following areas are ready for assessment: concrete paths leading to the property, outer siding, exterior/interior stairs, handrails (if required), crawl space (insulation and ventilation), smoke detectors, and window seals. Please note that this list aims to provide general information and should not be considered comprehensive.\n\nUpon the arrival of the building inspector, the property owner should have the building permit, building blueprints, and proof of ownership ready to present to the inspector. Failure to do so may result in a delay of the inspection or rescheduling at the owner's cost.\n\nApplicants may schedule either the Standard Service or Premium Service by calling 555-2044, extension 22, during regular business hours, which are Monday to Friday from 8 A.M. to 5 P.M.\n\nStandard Service:\nReceipt of Request | Scheduled Inspection\nMonday – Friday | One week later\n\nPremium Service:\nReceipt of Request | Scheduled Inspection\nMonday – Thursday | The following day\nFriday | The following Monday\n\nQuestions may be directed to Jeff Hesen at 555-2044, extension 40. Residential inspections will be carried out by Anthony Trevino (New Buildings) and Danielle Sullivan (Renovations). Commercial inspections will be carried out by Gerald Ross (New Buildings) and Paul Kotter (Renovations).\n\n---\n\nCertificate of Building Inspection\nCity of Meadowville\n\nPermit #: 489-301\n\nDate of Inspection: Thursday, February 20\nOwner: Rita Poole\n\nService Type: [√] Premium   [ ] Standard\nAddress: 2399 Worthington Drive\n\nResult: In Compliance\n\nInspector: Danielle Sullivan\nSignature: Danielle Sullivan", "qs": [{"n": 176, "q": "What is NOT mentioned as something that will be checked during the inspection?", "opts": ["Outdoor walkways", "Roof coverings", "The building's exterior", "Fire detection devices"], "ans": 1}, {"n": 177, "q": "In the information, the word \"aims\" in paragraph 1, line 4, is closest in meaning to", "opts": ["intends", "chooses", "proposes", "targets"], "ans": 0}, {"n": 178, "q": "What are applicants asked to do?", "opts": ["Submit photos of the property", "Prepare paperwork in advance", "Clean the property thoroughly", "Show proof of tax payments"], "ans": 1}, {"n": 179, "q": "When most likely did Ms. Poole make an inspection request?", "opts": ["On February 13", "On February 15", "On February 19", "On February 20"], "ans": 2}, {"n": 180, "q": "What is suggested about Ms. Poole?", "opts": ["She had renovations performed at her home.", "She lives in a newly constructed building.", "She did a remodeling project for her business.", "She is the owner of a commercial building."], "ans": 0}]}, {"title": "Questions 181-185 refer to the following table of contents and review.", "passage": "Team Dynamics: Building Effective Collaboration\nKL Publishing House\nIntroduction by Gisela Tate\n\nIntroduction ...... 1\nConflict Resolution Strategies ...... 36\nRavi Anagal, Owner, Venture Institute\nCommunication Patterns and Their Effect ...... 66\nArthur Lowell, Owner, KL Publishing House\nBoosting Motivation ...... 93\nFrank Melgar, President, Hanifan Sales\nDiversity in Decision-Making ...... 118\nGisela Tate, Professor, Dorsey University\nDefining Roles for Better Results ...... 146\nYun Lei, HR Consultant, Solutions Co.\n\nBook Review: Team Dynamics: Building Effective Collaboration\n\nThis book is useful for anyone who wants to understand how teams function. The publisher, KL Publishing House, is one of my favorites because its Web site has supplemental case studies, templates, checklists, and more. As the book's introduction provides foundational knowledge about managing teams in general, it would not be of much use to experienced managers. However, there are a lot of topics covered in the book's essays. Ravi Anagal's essay on conflict resolution provides numerous practical tools. I have already had the opportunity to try some of these strategies in my workplace, and they have been surprisingly successful. Ms. Lei's advice for defining roles within the team was sensible and constructive.\n\nI was deeply impressed with all of the essays in the book, with one exception. In my opinion, Frank Melgar's commentary on increasing motivation was not broad enough. His methods would only work well on recognition-oriented individuals, which is a small percentage of most employees. Overall, despite some shortcomings, I believe that reading this book is well worth your time.\n\n— Lucas Kemp", "qs": [{"n": 181, "q": "Who wrote the introduction to Team Dynamics: Building Effective Collaboration?", "opts": ["A university professor", "A company president", "A publishing company owner", "An HR consultant"], "ans": 0}, {"n": 182, "q": "What is indicated about KL Publishing House?", "opts": ["It is currently seeking new contributors.", "It solely publishes business-related books.", "It has been nominated for an award.", "It provides additional online resources."], "ans": 3}, {"n": 183, "q": "What does Mr. Kemp suggest about the book's introduction?", "opts": ["It covers a considerable variety of topics.", "It uses technical language aimed at experts.", "It is mainly appropriate for new managers.", "It describes the dynamics of his own team well."], "ans": 2}, {"n": 184, "q": "In the review, the word \"covered\" in paragraph 1, line 5, is closest in meaning to", "opts": ["concealed", "included", "protected", "invested"], "ans": 1}, {"n": 185, "q": "Where does Mr. Kemp's least favorite essay begin?", "opts": ["On page 66", "On page 93", "On page 118", "On page 146"], "ans": 1}]}, {"title": "Questions 186-190 refer to the following advertisement and e-mails.", "passage": "Get your business noticed with a print ad in The Daily Reporter. Our newspaper reaches over 80,000 readers a day, many of whom could be your next new customers. We can run advertisements for up to one full week, increasing the chances of your ads attracting new business. And, throughout the month of July, we're offering a special promotion on 5-line text-only advertisements for small businesses. Even if you currently have a membership discount with our publication, you may still take advantage of this promotion for further savings.\n\nDuration | Standard Price | July Promotional Price\n1 day | $35 | $25\n3 days | $95 | $80\n5 days | $140 | $115\n7 days | $180 | $150\n\nDon't miss your chance to promote your business for a great price! E-mail Marion Watt at m.watt@daily-reporter.com.\n\nTo: Marion Watt <m.watt@daily-reporter.com>\nFrom: Robert Hirschman <robert@flexhardware.com>\nDate: July 10, 9:23 A.M.\nSubject: My advertisement\n\nDear Ms. Watt,\n\nEarlier this week, I placed an order for an advertisement in The Daily Reporter for an anniversary sale that my hardware store is having this weekend. I paid the applicable $80 fee by credit card and e-mailed the information for the ad. Today was the first day that your newspaper ran the ad, and I was disappointed to see that it contained a number of errors.\n\nFirst of all, the ad was supposed to be in the Lifestyle section of the paper, but it was included in the Politics section. Also, I wanted the phone number at the top of the ad, along with the address, but you printed the address at the top and the phone number at the bottom. Finally, and most problematic, the ad said our hours of operation are daily from 8 A.M. to 8 P.M. While we do open daily at 8 A.M., we close earlier — at 7 P.M. — on the weekend. This was included in the information I sent, so I'm not sure what went wrong.\n\nPlease correct these errors before the next edition of the newspaper comes out.\n\nSincerely,\n\nRobert Hirschman\nOwner, Flex Hardware\nE-mail Message\n\nTo: Robert Hirschman <robert@flexhardware.com>\nFrom: Marion Watt <m.watt@daily-reporter.com>\nDate: July 10, 11:06 A.M.\nSubject: Re: My advertisement\n\nDear Mr. Hirschman,\n\nOn behalf of The Daily Reporter, please accept my sincerest apologies for the issues you experienced with your ad. The ad will be adjusted according to your specifications and the correct version will appear for the remainder of the time you paid for. We are currently running an internship program here at our publication, and occasionally, our interns are prone to making errors. To avoid any similar occurrences, I will review your ad myself this evening before the paper goes to press.\n\nIn addition, I have attached to this e-mail a voucher for a free one-week advertisement (5 lines). It can be used at any time, not just during our July promotional period. I hope this resolves the problem. If you have any questions about your current ad, or about using the voucher, please feel free to e-mail me.\n\nSincerely,\n\nMarion Watt\nAdvertising Editor, The Daily Reporter", "qs": [{"n": 186, "q": "What is indicated about the July promotion?", "opts": ["Discounts cannot be combined with other offers.", "Ms. Watt can write text for customers upon request.", "The special price is for new customers only.", "The advertisements cannot include images."], "ans": 3}, {"n": 187, "q": "How many days of advertising did Mr. Hirschman pay for?", "opts": ["One", "Three", "Five", "Seven"], "ans": 1}, {"n": 188, "q": "What is NOT indicated as a problem with the advertisement for Mr. Hirschman?", "opts": ["The business hours listed", "The street number of the business", "The section in which it was printed", "The placement of a phone number"], "ans": 1}, {"n": 189, "q": "What does Ms. Watt plan to do on July 10?", "opts": ["Personally check some information", "Provide Mr. Hirschman with details of an internship", "Issue a full refund to Mr. Hirschman", "Extend the duration of an advertisement"], "ans": 0}, {"n": 190, "q": "What is the standard value of the voucher given to Mr. Hirschman?", "opts": ["$35", "$95", "$140", "$180"], "ans": 3}]}, {"title": "Questions 191-195 refer to the following Web page, e-mail, and schedule.", "passage": "www.custer-library.org/news\n\nHOME | SEARCH | ACTIVITIES | NEWS | CONTACT\n\nCuster Library is seeking people to assist with library activities as well as administrative tasks from April until August. If you would like to share your time with us, please fill out an application at the library's circulation desk. Brief descriptions of our open tasks are listed below. Although these are unpaid roles, helpers will be provided with a free lunch and full borrowing access to all library collections. Be sure to include the task number on your application form.\n\nEvent Host/Hostess (Task #312)\nGreet visitors at library events, distribute program materials (if applicable), and answer questions about the library's facilities. You must be available for two evenings per month.\n\nInterlibrary Loan Assistant (Task #209)\nRetrieve books, CDs, and DVDs and prepare them for loans to other libraries. A strong knowledge of the library's layout and organizational system is required.\n\nBooks-On-Wheels Driver (Task #477)\nDrop off and pick up books during the day from members of the community who are unable to come to the branch in person. You must have your own vehicle and a valid driver's license. You will be reimbursed for gas usage.\n\nReaders Corner Tutor (Task #120)\nAssist in tutoring children and young adults in reading skills. You must commit to three sessions a week. Experience in teaching is a plus but is not required.\n\nTo: Joyce Clawson <clawsonj@pjinternet.com>\nFrom: Rebecca Blair <r.blair@custer-library.org>\nDate: April 4\nSubject: Application Accepted\n\nDear Ms. Clawson,\n\nThank you for your interest in helping out at Custer Library. Your application for Task #477 has been approved. All volunteers must attend a brief training session with our library director, Gretchen Howell, prior to beginning to work with us. The next session will be held on Tuesday, April 19, at 6 P.M. You will need to submit a recent photo when you come. This will be used for your library ID badge.\n\nWe really appreciate your assistance, and we look forward to working with you!\n\nSincerely,\n\nRebecca Blair\nProgram Coordinator, Custer Library\nLibrary Activities: Week of April 25\n\nDate | Time / Activity | Description | Recommended For\nMonday, April 25 | 9 A.M. – 10 A.M. / Skills Class | Learn the basics of word processing and sending e-mails on our laptops with Tom Manning. | Senior citizens\nTuesday, April 26 | 2 P.M. – 4 P.M. / Puppet Show | Led by Jimmy Winifred, stories come alive with colorful and playful puppets. | Preschool students (5 and under)\nThursday, April 28 | 5 P.M. – 6 P.M. / Craft Time | Gretchen Howell teaches you how to make your own decorative vase. Please bring three dollars for materials. | Ages 8-12\nFriday, April 29 | 7 P.M. / Poetry Reading | Share your own poems or simply listen to others reciting theirs. | All ages", "qs": [{"n": 191, "q": "What is the purpose of the Web page?", "opts": ["To outline new library policies", "To recruit temporary volunteers", "To announce a community lunch", "To promote new book collections"], "ans": 1}, {"n": 192, "q": "What is most likely true about Ms. Clawson?", "opts": ["She has experience in teaching.", "She has a driver's license.", "She is available in the evening.", "She is familiar with the library's layout."], "ans": 1}, {"n": 193, "q": "What is Ms. Clawson asked to do at the April 19 event?", "opts": ["Bring a picture of herself", "Make book recommendations", "Present an ID card", "Take a brief test"], "ans": 0}, {"n": 194, "q": "What can library patrons do on April 25?", "opts": ["Listen to some poetry", "Improve their research skills", "Learn how to use a computer", "Design a Web site"], "ans": 2}, {"n": 195, "q": "What is suggested about Craft Time?", "opts": ["It can be attended free of charge.", "It is intended for preschool children.", "It will be held twice a week.", "It is taught by the library director."], "ans": 3}]}, {"title": "Questions 196-200 refer to the following invoice, notice, and e-mail.", "passage": "Leblanc Supplies\n\nOrder Date: 14 May\nClient Account: 08478\nClient Industry: Garment\nClient Name: Swartz Incorporated\n\nItem # | Item Description | Price\nC8394 | Cotton jersey fabric, Dark purple, £8.50 per yard x 450 | £3,825.00\nS2011 | Silk fabric, Dark purple, £28.75 per yard x 50 | £1,437.50\nF7466 | Black zipper, 3 mm x 50 cm, £1.75 each x 100 | £175.00\nF8293 | * Gold effect buttons, 10 mm, £0.65 each x 300 | £195.00\nShipping | £50.00\nTotal Due | £5,682.50\n\nLeblanc Rewards Club Points Earned: 5,877\n* May featured item\n\nPlease note that Leblanc Supplies is making changes from next month. These are outlined in the enclosed notice.\n\nNotice to All Leblanc Supplies Customers\n\nFrom 1 June, we will take more time to check for pricing accuracy before issuing an invoice. Currently, invoices are issued on the same day as the order, but under the new system, they will be sent 3 days later. Customers will still have 1 month to make returns or exchanges of unused goods.\n\nThe opportunities to earn points through our loyalty program will remain the same. One point will be earned per pound spent, and one bonus point per pound will be issued for the following:\n\n• Bulk orders of 500 yards or more of a single fabric\n• Repeat orders that continue for at least three months\n• The purchase of the featured item of the month\n• Funds spent with our business partner, Felosa Logistics\nE-mail Message\n\nTo: Rohan Joshi <rjoshi@leblancsupplies.co.uk>\nFrom: Marilyn Flannery <mflannery@leblancsupplies.co.uk>\nDate: 27 June\nSubject: Invoices\n\nHi Rohan,\n\nI've just received an e-mail from Patrick Gordon of Anaheim Fashions. He placed an order on 21 June, and although the goods were delivered, he never received an invoice. I've issued a new one for him manually, and I have contacted him by phone to apologize for this oversight. If there is some kind of issue with the invoicing software, Mr. Gordon may not be the only customer affected. Could you please look into the matter to find out if there are any others? Delays like this could put too much pressure on our cash flow situation and may even lead to a loss of valued clients.\n\nThank you,\n\nMarilyn", "qs": [{"n": 196, "q": "What does the invoice indicate about Swartz Incorporated?", "opts": ["It creates graphic designs.", "It requested next-day shipping.", "It manufactures clothing.", "It ordered two colors of fabric."], "ans": 2}, {"n": 197, "q": "Why most likely did Swartz Incorporated receive bonus points?", "opts": ["For purchasing some buttons", "For patronizing Leblanc Supplies' partner", "For placing a bulk order over a certain size", "For repeating the same order for several months"], "ans": 0}, {"n": 198, "q": "What change does the notice inform customers about?", "opts": ["An expansion of payment options", "An arrangement with a new delivery provider", "An extension of a product return period", "A revised timeline for issuing a document"], "ans": 3}, {"n": 199, "q": "When should Mr. Gordon have received an invoice?", "opts": ["On 21 June", "On 22 June", "On 24 June", "On 27 June"], "ans": 2}, {"n": 200, "q": "What does Ms. Flannery ask Mr. Joshi to do?", "opts": ["Check for some similar problems", "Make an apology to Mr. Gordon", "Upgrade some invoicing software", "Send a new invoice to Mr. Gordon"], "ans": 0}]}]}, "t2": {"p5": [{"n": 101, "en": "Ms. Mitchell had to borrow a laptop from the IT department because ______ was malfunctioning.", "opts": ["she", "herself", "her", "hers"], "ans": 3}, {"n": 102, "en": "We provide a complete refund for all returns made within 10 days of purchase, ______ any shipping fees.", "opts": ["minus", "on", "down", "behind"], "ans": 0}, {"n": 103, "en": "The courier cannot make the delivery to the correct location unless the ______ have an address printed on them.", "opts": ["layouts", "packages", "routes", "deposits"], "ans": 1}, {"n": 104, "en": "The airport check-in counter cannot issue the boarding pass ______ the luggage is weighed.", "opts": ["yet", "for", "into", "until"], "ans": 3}, {"n": 105, "en": "Please ______ a unique username and password, and do not share this information with anyone.", "opts": ["continue", "plan", "remain", "create"], "ans": 3}, {"n": 106, "en": "Mr. Winslow will go sightseeing in New York for a few hours ______ he completes his business meeting.", "opts": ["often", "every", "either", "after"], "ans": 3}, {"n": 107, "en": "To ensure security, the bank sends a notification for every ______ made on your account.", "opts": ["resource", "transaction", "foundation", "qualification"], "ans": 1}, {"n": 108, "en": "The technician ______ diagnosed the issue with the packing machine, minimizing downtime for the factory.", "opts": ["experts", "expertly", "expertise", "expert"], "ans": 1}, {"n": 109, "en": "The event's policy clearly indicates that the tickets purchased are not ______ and must be used by the original buyer.", "opts": ["transferable", "transfers", "transferred", "transfer"], "ans": 0}, {"n": 110, "en": "The project manager provided detailed schedules and estimated ______ to ensure the team stays on track and within budget.", "opts": ["considerations", "responses", "drawbacks", "costs"], "ans": 3}, {"n": 111, "en": "Mr. Thomas ______ to complete all of his assigned tasks before he left for his three-week vacation to Singapore.", "opts": ["achieved", "controlled", "operated", "managed"], "ans": 3}, {"n": 112, "en": "Evergreen Footwear is ______ on the latest advertising campaign to boost its shoe sales.", "opts": ["predicting", "believing", "counting", "turning"], "ans": 2}, {"n": 113, "en": "The participants who had perfect class ______ for the entire fall session were recognized by the instructor.", "opts": ["attendant", "attended", "attendance", "attends"], "ans": 2}, {"n": 114, "en": "Thanks to the office's many windows, the rooms stay bright ______ the day even with the lights off.", "opts": ["while", "during", "onto", "beside"], "ans": 1}, {"n": 115, "en": "______ used as a ceramics factory, the Lunetta Building is now a modern office complex.", "opts": ["Formerly", "Merely", "Precisely", "Exactly"], "ans": 0}, {"n": 116, "en": "______ the drug is approved for human trials, it will still be several years before Jasmine Pharmaceuticals can sell it.", "opts": ["At least", "Even if", "As much as", "Due to"], "ans": 1}, {"n": 117, "en": "There were plenty of security personnel at yesterday's outdoor concert because the event planners ______ crowds.", "opts": ["had anticipated", "anticipate", "would anticipate", "are anticipating"], "ans": 0}, {"n": 118, "en": "Cev Technology's customer service response times are notably quicker ______ to industry standards.", "opts": ["compares", "compared", "compare", "comparison"], "ans": 1}, {"n": 119, "en": "______ increased demand, Lundy Manufacturing has accelerated its production schedule by hiring temporary workers.", "opts": ["Owing to", "Now that", "Instead of", "Everywhere"], "ans": 0}, {"n": 120, "en": "The guests were ______ greeted by the ground crew when they arrived at the airport.", "opts": ["enthusiastic", "enthusiastically", "enthusiast", "enthusiasm"], "ans": 1}, {"n": 121, "en": "Traffic will be diverted from Pritchard Avenue as the Department of Transportation ______ the faded lines on the road.", "opts": ["repaints", "repainting", "is repainted", "to be repainted"], "ans": 0}, {"n": 122, "en": "The original plans for the festival went well over the budget and ______ required additional funding from sponsors to proceed.", "opts": ["consequently", "previously", "whereas", "for instance"], "ans": 0}, {"n": 123, "en": "All job applicants are required to take a computer-based personality test ______ their interview.", "opts": ["out of", "prior to", "such as", "except for"], "ans": 1}, {"n": 124, "en": "The consultant urged the company ______ the compliance issues promptly to avoid penalties.", "opts": ["will be resolved", "to resolve", "resolve", "to be resolved"], "ans": 1}, {"n": 125, "en": "Two companies have presented bids for the roadwork repairs, but city officials have not decided ______ will be selected.", "opts": ["whenever", "if", "that", "which"], "ans": 3}, {"n": 126, "en": "Cheshire Inc.'s policy changes had ______ effects on the company's overall efficiency.", "opts": ["considerably", "considerable", "consideration", "consider"], "ans": 1}, {"n": 127, "en": "Team leaders at Hamilton Enterprises always communicate and cooperate with each other to prevent ______ conflicts.", "opts": ["recent", "internal", "advisable", "seasonal"], "ans": 1}, {"n": 128, "en": "The new accounting software will undergo several rounds of testing before it ______ to the public.", "opts": ["released", "is released", "will release", "is releasing"], "ans": 3}, {"n": 129, "en": "According to the quarterly report, it became ______ that our employee productivity had improved since the equipment upgrades.", "opts": ["supplemental", "extensive", "apparent", "inevitable"], "ans": 2}, {"n": 130, "en": "Due to many positive reviews from ______, Ms. Howard purchased the first novel in the Bright Wonders series.", "opts": ["critical", "critically", "criticizing", "critics"], "ans": 3}], "p6": [{"title": "Questions 131-134 refer to the following introduction.", "text": "Welcome to the Occupation Assessment Questionnaire. This tool (131)______ to assist you in identifying your strengths and interests, helping you to better understand where your skills and passions align. By completing this questionnaire, you'll gain valuable insights into career paths that best (132)______ your unique profile. You will answer a series of twenty-five questions, each carefully crafted to evaluate different aspects of your personality, preferences, and abilities. (133)______. Thoughtful responses will lead to more accurate and meaningful results.\n\nRemember, while this questionnaire can provide useful guidance, it only shows general trends rather than definitive solutions. You may want to speak to a career counselor to discuss your situation (134)______ before setting your sights on a career path.", "qs": [{"n": 131, "opts": ["designs", "is designed", "designed", "designing"], "ans": 1}, {"n": 132, "opts": ["adapt", "enforce", "claim", "match"], "ans": 3}, {"n": 133, "opts": ["You had the highest score among all the participants in the survey.", "Please take your time to reflect on each question before answering.", "You are welcome to get in touch with us if you need further assistance.", "Based on the answers provided, a career in sales would suit you well."], "ans": 1}, {"n": 134, "opts": ["specific", "specifically", "specifying", "specify"], "ans": 1}]}, {"title": "Questions 135-138 refer to the following e-mail.", "text": "To: allstaff@bowen-digital.com\nFrom: djarvis@bowen-digital.com\nDate: March 22\nSubject: Office visit\n\nWe are excited to inform you that investors from overseas will be visiting our office next Friday. This visit is a (135)______ opportunity for us to demonstrate our expertise and strong commitment to cybersecurity. Around nine o'clock, Isabella Bartlett will lead our guests on a tour of the office. She (136)______ here for nearly twenty years and is well-acquainted with every aspect of our operations. Her extensive experience and detailed knowledge will be instrumental in showcasing our capabilities.\n\nThroughout the day, the investors will be introduced to team members and provided with insights into our current projects. (137)______. This is not only a chance to impress our visitors but also an opportunity to potentially secure future investments. Your (138)______ will play a crucial role in making this visit a success.\n\nAll the best,\n\nDylan Jarvis", "qs": [{"n": 135, "opts": ["grateful", "steady", "cautious", "valuable"], "ans": 3}, {"n": 136, "opts": ["is working", "will be working", "has been working", "works"], "ans": 2}, {"n": 137, "opts": ["The building's layout may be confusing at first with its winding hallways.", "Please be prepared to offer information about your work if you do meet them.", "Their company is gaining ground in the market, strengthening its presence.", "The investment process is running smoothly, with each stage being efficiently managed."], "ans": 1}, {"n": 138, "opts": ["professional", "profession", "professionally", "professionalism"], "ans": 3}]}, {"title": "Questions 139-142 refer to the following advertisement.", "text": "Enhance your restaurant's takeout service with top-quality containers from Maclagan Supplies. With insulation to keep food warm, our products ensure your customers enjoy their meals at the perfect (139)______. In addition, our sauce vessels are leak-proof, preventing spills and unnecessary mess. Most of our competitors' containers are made from materials that can only be thrown away. (140)______, ours are fully recyclable, helping your customers to reduce waste.\n\nWhen it comes to takeout packaging, we understand that each restaurant requires specific sizes and shapes. For this reason, you may request a free sample to check the (141)______ and value yourself. Plus, you can set up automatic reordering. (142)______. Call us today at 555-8024 and allow us to enhance your food delivery services!", "qs": [{"n": 139, "opts": ["proportion", "serving", "temperature", "combination"], "ans": 2}, {"n": 140, "opts": ["By contrast", "Rather", "On one hand", "Furthermore"], "ans": 0}, {"n": 141, "opts": ["suited", "suitably", "suitable", "suitability"], "ans": 3}, {"n": 142, "opts": ["You'll be able to review your order history online.", "We offer flexible payment options for bulk purchases.", "That way, you'll always have what you need in stock.", "Our team can assist you with special orders for seasonal items."], "ans": 2}]}, {"title": "Questions 143-146 refer to the following announcement.", "text": "Experience the beauty of Oriana National Park during our upcoming public event! (143)______. Your guide will lead you on an intermediate-level hike that lasts for approximately two hours. The highlight will be a cliff (144)______ gorgeous Walder Valley. You will also learn to identify native flowers and trees. Good weather is expected, but there is always the possibility that there will be rain. (145)______, we will provide the necessary waterproof clothing and also arrange some indoor activities. Fortunately, we have recently made upgrades to the trails. In addition to improved signage, (146)______ have handrails in steep areas that may become slippery when wet. Benches have also been placed at scenic spots along the route for those who want to rest or take in the beauty of the surroundings.\n\nThis event is a great way to enjoy nature, learn about the park's rich ecosystem, and spend time outdoors with fellow nature lovers. To sign up, visit www.oriananatlpark.com/activities.", "qs": [{"n": 143, "opts": ["All donations will be used to repair park trails.", "We will hold a group walk at 9 A.M. on June 14.", "Everyone enjoyed the stunning photographs of the area.", "The park has been used in several popular shows and movies."], "ans": 1}, {"n": 144, "opts": ["overlooked", "overlook", "overlooks", "overlooking"], "ans": 3}, {"n": 145, "opts": ["If so", "After all", "Instead", "Otherwise"], "ans": 0}, {"n": 146, "opts": ["yours", "theirs", "they", "any"], "ans": 2}]}], "p7": [{"title": "Questions 147-148 refer to the following receipt.", "passage": "Terry's Corner Shop\n\n141 Taylor Street\nWinnipeg, Manitoba\nR3B 0Y3\n(514) 555-1358\n\nGC Lemonade (1 L)          $3.50\nGC Lemonade (1 L)          $3.50\nBlitz Cola (355 mL)        $1.20\nAce Bottled Tea (500 mL)   $2.95\nSales Tax                  $0.56\n\nTotal Due                  $11.71\n\nElectronic payment processed via credit card on June 26 at 10:00 A.M. Thank you for your patronage!\n\nWe are open 7 days a week. From July 1, we will start staying open until 11 P.M. daily to better serve the needs of our loyal customers.", "qs": [{"n": 147, "q": "What was purchased at Terry's Corner Shop?", "opts": ["Cleaning products", "Fruit", "Snacks", "Beverages"], "ans": 3}, {"n": 148, "q": "What is true about Terry's Corner Shop?", "opts": ["It will change its hours of operation.", "It waives the sales tax on specific purchases.", "It currently opens for business at 10 A.M.", "It has more than one branch in Winnipeg."], "ans": 0}]}, {"title": "Questions 149-150 refer to the following information.", "passage": "ATTENTION! READ BEFORE PROCEEDING.\n\nThank you for choosing Ocello Framing. As you unwrap this finished product, please handle it with care and avoid using sharp objects to remove the protective padding, as this could potentially damage the frame or artwork. Your frame has been carefully cut and assembled to ensure a perfect fit for your treasured piece. To maintain its pristine condition, dust the frame regularly with a soft, dry cloth. Do not apply sprays, cleaners, or any chemical products, as these can damage the frame's finish over time. We also recommend hanging the frame out of direct sunlight, as prolonged exposure to sunlight can cause fading and deterioration of both the frame and the artwork. Additionally, keep the frame away from areas with excessive humidity. Should you require further assistance, please contact us at 382-555-1940. We hope you enjoy the beauty of your framed artwork for years to come.", "qs": [{"n": 149, "q": "Where most likely would this information be seen?", "opts": ["In a brochure", "Inside a package", "On a Web site", "On a bulletin board"], "ans": 1}, {"n": 150, "q": "What recommendation is made in the information?", "opts": ["Apply polish to the frame regularly.", "Avoid using cleaning solutions.", "Remove protective material with scissors.", "Hang the artwork in natural light."], "ans": 1}]}, {"title": "Questions 151-152 refer to the following text-message chain.", "passage": "Riya Agarwal [8:40 A.M.]\nHi, Dean. I'm at the café now ordering lunch for the teambuilding session. I know your talk starts at 11:30. Should the lunches be delivered at noon, or would 1:00 be better?\n\nDean Meachum [8:41 A.M.]\nI have a lot to cover.\n\nRiya Agarwal [8:44 A.M.]\nGot it. I'll be back at the office in about fifteen minutes. Is the room set up yet?\n\nDean Meachum [8:45 A.M.]\nI'm headed there now. What do you need?\n\nRiya Agarwal [8:46 A.M.]\nWell, the chairs in the meeting room are all in rows facing the whiteboard, but I'd prefer to have them in a big circle. It's a better setup for the participants to engage in group discussions and activities.\n\nDean Meachum [8:47 A.M.]\nNo problem. I'll take care of it.", "qs": [{"n": 151, "q": "At 8:41 A.M., what does Mr. Meachum most likely mean when he writes, “I have a lot to cover”?", "opts": ["He does not have time to help Ms. Agarwal.", "He plans to skip lunch today.", "He thinks a delivery should be later.", "He wants to hire someone quickly."], "ans": 2}, {"n": 152, "q": "What will Mr. Meachum most likely do next?", "opts": ["Greet event participants", "Remove a whiteboard", "Plan some group activities", "Rearrange some furniture"], "ans": 3}]}, {"title": "Questions 153-154 refer to the following announcement.", "passage": "Join us for Fairview's Second Annual Film Appreciation Day on Saturday, November 16, a day dedicated to celebrating the art of cinema. From 9:00 A.M. to 11:00 P.M., immerse yourself in a carefully curated selection of classic and contemporary films at the historic Plaza Theater. Whether you're a fan of timeless masterpieces or the latest blockbusters, there's something for everyone in our diverse lineup of screenings. For added convenience, visit www.plazatheaterfilms.com to view the theater's seating layout, get driving directions, and explore the snack bar options. Make sure to take advantage of special offers — coupons for discounted movie tickets are available at various local businesses and can also be picked up at the Parks and Recreation Department at City Hall. Early bird ticket holders will also receive a free commemorative poster designed by a local artist, so be sure to arrive early. Don't miss this opportunity to immerse yourself in a fantastic cinematic experience that will delight film lovers of all ages. We hope to see you there!", "qs": [{"n": 153, "q": "What is indicated about Film Appreciation Day?", "opts": ["It was held for the first time last year.", "It is being hosted by several theaters.", "Its profits will be donated to local causes.", "It will include speeches by filmmakers."], "ans": 0}, {"n": 154, "q": "According to the announcement, what can people do on the Web site?", "opts": ["Browse a menu", "Reserve seats", "Download coupons", "View some video clips"], "ans": 0}]}, {"title": "Questions 155-157 refer to the following advertisement.", "passage": "Pearl Dental Clinic\n\n225 Hillcroft Street • 402-555-7378\n\nDiscover top-notch dental care from Pearl Dental Clinic! We have recently hired three more full-time dentists, which means our patient capacity has almost doubled! Anyone who wishes to register with our clinic should call us on the number listed above or come into the clinic in person. Our experienced team members are all highly qualified and can assist you with routine check-ups and cleanings, teeth whitening, dental implants, and more. For a comprehensive list, visit www.pearldental.net. We accept a broad range of plans from insurance providers, so many of our standard treatments are likely covered by your current plan. In addition, our patients are eligible to use emergency dental care, which means you can see a dentist at any time, day or night, if necessary. We look forward to giving you a beautiful and healthy smile at Pearl Dental.", "qs": [{"n": 155, "q": "What can the business do because of a recent change?", "opts": ["Upgrade dental equipment", "Lower check-up fees", "Send appointment notifications", "Accept additional patients"], "ans": 3}, {"n": 156, "q": "According to the advertisement, why should people visit the Web site?", "opts": ["To access a list of clinic employees", "To get driving directions to the clinic", "To view all available treatments", "To find the nearest branch of a business"], "ans": 2}, {"n": 157, "q": "What is indicated about Pearl Dental patients?", "opts": ["They must purchase insurance from the clinic.", "They can access care whenever they need it.", "They may be eligible for a discount on services.", "They should book their appointments online."], "ans": 1}]}, {"title": "Questions 158-160 refer to the following letter.", "passage": "Midway Water Company\n56 Riverside Plaza\nNEWPORT\nNR29 0EB\n19 August\n\nDear Ms. Howarth,\n\nWe are writing to inform you of an outstanding water bill amounting to £83.25 for the property located at 22 Stroude Road, Newport. Our records show that you vacated the premises on 5 July, yet the final payment for your account remains unsettled. Failure to resolve this matter may result in additional charges, including late fees or potential legal action. — [1] —.\n\nTo assist you in settling the issue, we would like to outline the steps you can take. — [2] —. First, you may visit our official Web site at www.midwaywater.co.uk, where you can enter your unique account number to proceed with the online payment. This method is secure and available 24/7 for your convenience. — [3] —. Alternatively, you can call our customer service line at 080-261-4545. Our agents will be happy to assist you in making the payment over the phone using your credit card. We strongly urge you to address this outstanding balance immediately to avoid any further complications. Should you have any questions or concerns, feel free to contact us anytime. — [4] —.\n\nSincerely,\nToby Cunningham\nToby Cunningham\nCustomer Service Agent, Midway Water", "qs": [{"n": 158, "q": "What is the purpose of the letter?", "opts": ["To issue a partial refund", "To detail an insufficient balance", "To request a payment", "To confirm an account closure"], "ans": 2}, {"n": 159, "q": "What is indicated in the letter about Ms. Howarth?", "opts": ["She informed Midway Water that she lost her account number.", "She has been charged a late fee by Midway Water.", "She has difficulty accessing her online account.", "She recently moved out of a property on Stroude Road."], "ans": 3}, {"n": 160, "q": "In which of the positions marked [1], [2], [3], and [4] does the following sentence best belong? \"You can choose the method that suits you best.\"", "opts": ["[1]", "[2]", "[3]", "[4]"], "ans": 1}]}, {"title": "Questions 161-163 refer to the following article.", "passage": "SEATTLE (February 18) — In a night that highlighted the growing importance of corporate responsibility, the state government honored Allcot Telecommunications with the inaugural EcoVision Prize at a ceremony held at the Ewing Hotel in Seattle. The event, which drew an array of business leaders, environmental advocates, and government officials, celebrated companies that have made significant strides in sustainable practices. The EcoVision Prize is a newly established award, conceived to recognize and reward excellence in environmental stewardship within the business community. Nominees must have been operating within the state of Washington for a minimum of two years and have a staff size of at least fifty. The evaluation criteria included a variety of categories such as minimizing waste, lowering emissions, and fostering community engagement in environmental initiatives. Liam Dreyer, the CEO of Allcot Telecommunications, and several other high-ranking executives represented the company at last night's ceremony.\n\n\"We understand the importance of growing our business responsibly,\" said Mr. Dreyer. \"Our long-term vision ensures that we will be able to reach more customers while protecting our precious planet.\"", "qs": [{"n": 161, "q": "What is the purpose of the article?", "opts": ["To discuss sustainable practices", "To announce an award winner", "To analyze an industry trend", "To profile a new business"], "ans": 1}, {"n": 162, "q": "What is NOT indicated about Allcot Telecommunications?", "opts": ["Its headquarters is built with eco-friendly materials.", "Its leadership attended an event in Seattle.", "It has been in business for at least two years.", "It currently has fifty or more employees."], "ans": 0}, {"n": 163, "q": "The word \"reach\" in paragraph 2, line 2, is closest in meaning to", "opts": ["accomplish", "extend", "serve", "touch"], "ans": 2}]}, {"title": "Questions 164-167 refer to the following e-mail.", "passage": "E-mail Message\n\nTo: Kaliski Appliances <contact@kaliskiappliances.com>\nFrom: Erica Simpson <e_simpson@bellmail.net>\nDate: September 13\nSubject: K780 washing machine\n\nTo Whom It May Concern:\n\nI purchased a Kaliski washing machine, model K780, a few months ago, and it was running fine at first. However, for the past few days, when I opened the detergent drawer after a wash cycle, I could see that there was still a layer of soap left behind. This told me that the detergent was not dispensing properly. Indeed, my clothing is not coming out as clean as it should be. It seemed to be the worst when I set the machine to initiate a hot wash, which leads me to believe there is a problem with the programming of the appliance.\n\nAfter reading the user manual, I cleaned the drawer thoroughly and checked for blockages. I also ran several rinse cycles in an effort to resolve the issue. Unfortunately, neither of these strategies worked. It is imperative that I have this problem dealt with as soon as possible. I have some relatives coming to my home next week, and being without a washing machine is a major inconvenience for me. Please let me know what can be done about this.\n\nSincerely,\n\nErica Simpson", "qs": [{"n": 164, "q": "How did Ms. Simpson realize there was a problem with her washing machine?", "opts": ["She saw dark stains on her clothing after a wash cycle.", "She observed a residue remaining in a compartment.", "She had difficulty opening a detergent drawer.", "She could not set the appliance to perform a hot wash."], "ans": 1}, {"n": 165, "q": "Why does Ms. Simpson mention a user manual?", "opts": ["To seek clarification on some technical terms", "To point out an error she found in some information", "To request a copy of a missing document", "To emphasize measures she has already taken"], "ans": 3}, {"n": 166, "q": "The word \"ran\" in paragraph 2, line 2, is closest in meaning to", "opts": ["accelerated", "repeated", "operated", "mobilized"], "ans": 2}, {"n": 167, "q": "What is indicated about Ms. Simpson?", "opts": ["She owns other Kaliski products.", "She will host some visitors soon.", "She expects to exchange a machine.", "She thinks her item is still under warranty."], "ans": 1}]}, {"title": "Questions 168-171 refer to the following Web page.", "passage": "www.southsails.com/discussion_board\n\nI have been a subscriber to South Sails magazine for about three years, and it has been a great resource for me. I'm wondering if anyone living in the Bevan Bay area can help me decide on the best marina for my 25-foot sailboat. — [1] —. At first, I was considering Jasper Cove, but I am trying to figure out whether the negative aspects outweigh the positive ones. Because I signed up to receive South Sails for twelve months, I can get 10% off fees at Jasper Cove, but it doesn't seem to offer as many amenities as other sites. In addition, the on-site parking there is limited, which is a problem in the peak season. Windward Marina has a number of partners in its network. — [2] —. I do plan to take some multi-day trips this season, so it may be worth the higher fees. I also know that Duneview has on-site engineers who could fix any technical problems with my boat, but since I often carry out those kinds of tasks myself, that service isn't a benefit to me. — [3] —. However, their security system is impressive, and I do like the thought of my boat being safe and secure at all times. There are many factors to consider, so any insights you all could share would be greatly appreciated. — [4] —.\n\n— Leo Magnus", "qs": [{"n": 168, "q": "Why did Mr. Magnus write the post?", "opts": ["To suggest an article for a magazine", "To advertise a used boat for sale", "To recommend a marina for docking", "To request advice from local residents"], "ans": 3}, {"n": 169, "q": "What is mentioned about Jasper Cove?", "opts": ["It charges its customers for on-site parking.", "It offers discounts to one-year magazine subscribers.", "It is only open during the peak season.", "It is where South Sails customers have their meetings."], "ans": 1}, {"n": 170, "q": "What is indicated about Mr. Magnus?", "opts": ["He has experience in boat repairs.", "He has had his sailboat for three years.", "He got a security upgrade for his boat.", "He recently started a job near Bevan Bay."], "ans": 0}, {"n": 171, "q": "In which of the positions marked [1], [2], [3], and [4] does the following sentence best belong? \"This provides options for overnight docking on longer journeys.\"", "opts": ["[1]", "[2]", "[3]", "[4]"], "ans": 1}]}, {"title": "Questions 172-175 refer to the following online chat discussion.", "passage": "Reuben Mathis [10:05 A.M.]: Good morning. I've just checked with the print shop, and it will take about five days to get our banners back.\nAlba Salvato [10:06 A.M.]: Thanks for the update. Those will look great at our booth at the automotive trade show. They'll also make decorating our space a lot easier.\nReuben Mathis [10:07 A.M.]: Exactly. They'll definitely add a professional touch to our booth. And since the banners only feature our company logo and contact information, we'll be able to reuse them in the future. It's great to have something versatile.\nFlorence Judd [10:08 A.M.]: That's good to hear. However, we still need to get the brochure printed though. Alba, have you determined whether the Zappia model or Labrie-7 model will be on the cover?\nAlba Salvato [10:09 A.M.]: I don't want to rush it.\nFlorence Judd [10:10 A.M.]: I understand. Maybe you should talk to someone on the sales team to get a second opinion.\nAlba Salvato [10:11 A.M.]: Great idea. I'll speak to Ben Hague. He's back in the office tomorrow. And I'll have an answer for you by Wednesday or Thursday, Florence. Is that alright?\nFlorence Judd [10:13 A.M.]: Wednesday would be better, if possible. That way, I'll have enough time to finalize the flyer's design by Friday morning and avoid any last-minute rush.\nAlba Salvato [10:14 A.M.]: Sure thing. I can make that work.", "qs": [{"n": 172, "q": "What is indicated about the banners?", "opts": ["They were completed and shipped five days ago.", "They will be used at an industry event.", "They include details about some products.", "They have been used at previous trade shows."], "ans": 1}, {"n": 173, "q": "At 10:09 A.M., what does Ms. Salvato most likely mean when she writes, “I don’t want to rush it”?", "opts": ["She wants to change a meeting time.", "She will work additional hours.", "An express service is expensive.", "A decision should be made carefully."], "ans": 3}, {"n": 174, "q": "Who most likely is Mr. Hague?", "opts": ["A journalist", "A business owner", "A graphic designer", "A salesperson"], "ans": 3}, {"n": 175, "q": "When does Ms. Salvato plan to send some information?", "opts": ["Tomorrow", "Wednesday", "Thursday", "Friday"], "ans": 1}]}, {"title": "Questions 176-180 refer to the following schedule and e-mail.", "passage": "Northbrook Farm Festival\nSchedule of Events\n\nSaturday, October 11\n10:00 A.M. Tractor Rides, meet at the Main Tent\nRide in a trailer pulled by a tractor and take in the beauty of the farm.\n\n2:00 P.M. Pumpkin Painting Contest, Outbuilding #2\nShow off your painting skills with this fun event. You may even win a prize!\n\nSunday, October 12\n11:00 A.M. Dairy Milking Showcase, Outbuilding #1\nWatch Farmer Ted show you traditional and modern techniques for milking a cow.\n\n3:00 P.M. Barn Vibes, Willow Barn\nLearn some new dance moves from instructor Jessie Bray.\n\nBoth Days (all day)\n- Food trucks selling a variety of gourmet treats\n- Live performances from local musicians\n- Agriculture booths teaching visitors about life on the farm\n\nThe festival will take place rain or shine, and our team of friendly volunteers will be on hand to help you! We had around 250 attendees when the event took place in September last year, and we anticipate an even higher turnout this year. Although there is no charge to attend, wristbands will be given to event attendees at the main entrance, and these can be shown at some food trucks for free samples. For more information, visit www.northbrook-farm.com/events.\nTo: Undisclosed Recipients\nFrom: Madison Percy <mpercy@northbrook-farm.com>\nDate: October 9\nSubject: Festival activity change\n\nHi everyone,\n\nDue to unforeseen circumstances, we have had to cancel the milking demonstration at this weekend's festival. Unfortunately, the farmer who was supposed to lead the session will be unable to participate in the event due to his heavy workload. Instead, a cheese-making workshop will take place at the same time and place as the original activity. We will announce this change on our social media page, and we do not anticipate any change to the number of attendees.\n\nWhen you arrive for your shift, please check in with me at Outbuilding #1. We have also added a first aid station in the main tent, where a registered nurse will be available to help attendees with minor wounds such as cuts and bruises. If anyone is seeking such help, please direct them to the right place.\n\nThank you,\n\nMadison", "qs": [{"n": 176, "q": "What is NOT an activity that attendees can participate in on the first day of the festival?", "opts": ["Joining an art competition", "Tasting some food", "Taking a dance lesson", "Listening to live music"], "ans": 2}, {"n": 177, "q": "What is suggested about the festival?", "opts": ["Space is limited to 250 attendees.", "It may be rescheduled if bad weather occurs.", "Attendees will pay no admission fee.", "It is held in mid-October every year."], "ans": 2}, {"n": 178, "q": "In the e-mail, the word \"supposed\" in paragraph 1, line 2, is closest in meaning to", "opts": ["invited", "proposed", "assumed", "meant"], "ans": 1}, {"n": 179, "q": "When can event attendees learn how to make cheese?", "opts": ["At 10:00 A.M. on October 11", "At 2:00 P.M. on October 11", "At 11:00 A.M. on October 12", "At 3:00 P.M. on October 12"], "ans": 2}, {"n": 180, "q": "Who most likely is the e-mail intended for?", "opts": ["Medical personnel", "Festival ticket holders", "Event volunteers", "Food vendors"], "ans": 2}]}, {"title": "Questions 181-185 refer to the following job posting and letter.", "passage": "Bruni Construction is actively seeking a motivated and detail-oriented Assistant Site Manager to join our dynamic team. This position offers a unique opportunity for individuals with a strong construction background who are eager to transition from hands-on work to a supervisory role. As an Assistant Site Manager, you will be tasked with overseeing progress at 12~15 construction sites located in and around the Jacksonville area, ensuring that projects are on track and meeting quality standards. Additionally, you will spend one day a week at our headquarters, engaging in office-based tasks that support site operations. The position is offered as a six-month contract, with the possibility of renewal. During your tenure, Bruni Construction will put you through the necessary courses for you to receive certification in construction management. All fees will be covered by the company, including any accommodation and transportation costs incurred.\n\nIf you are interested in this exciting opportunity and meet the qualifications, we encourage you to apply. Please submit your application to Bruni Construction, 3196 Mercer Avenue, Jacksonville, FL 32256, no later than February 27. Immediate availability is preferred.\n\nTo apply, please include the following documents with your submission: a detailed résumé highlighting your relevant experience in construction, a cover letter explaining your interest in the role, and a portfolio that showcases your accomplishments in the field.\n\n---\n\nCameron Mattner\n460 Everett Street\nJacksonville, FL 32211\n\nFebruary 22\n\nBruni Construction\n3196 Mercer Avenue\nJacksonville, FL 32256\n\nTo Whom It May Concern:\n\nI am writing to express my interest in the Assistant Site Manager role at Bruni Construction. I have been self-employed in the construction industry for eight years. While my business has been successful and I enjoy having no stressful commute, working independently has often felt isolating. As a result, I am now seeking a position in a large company where I can engage with colleagues. I have excellent organizational and people skills, and I am already familiar with building regulations for the area. For example, in my current role, I need to ensure compliance with RTCC and BSHA on a daily basis. I have enclosed all of the requested documents as per the job listing, and I am confident that these will show that I am highly qualified for the advertised position.\n\nThank you for considering my application, and I look forward to hearing from you.\n\nSincerely,\n\nCameron Mattner", "qs": [{"n": 181, "q": "What is NOT suggested about the role?", "opts": ["It is intended for someone new to management.", "It requires a minimum number of years in the field.", "It involves working at more than one location.", "It may extend beyond the proposed period."], "ans": 1}, {"n": 182, "q": "According to the job posting, what will be available to the job recipient?", "opts": ["The option to work flexible hours", "Discounts on certain products", "The use of a company vehicle", "Professional development courses"], "ans": 3}, {"n": 183, "q": "Why does Mr. Mattner want to give up his current role?", "opts": ["He prefers hands-on work to a supervisory role.", "He wants to work alongside others.", "He would like more stability in his job.", "He aims to reduce his commuting time."], "ans": 1}, {"n": 184, "q": "What is true about Mr. Mattner?", "opts": ["He provided some examples of his previous work.", "He was recommended by a Bruni Construction employee.", "He missed the deadline for the application.", "He sent his application documents to the wrong address."], "ans": 0}, {"n": 185, "q": "What most likely is RTCC?", "opts": ["A community-based nonprofit organization", "A staffing and recruitment agency", "A financial assistance program for businesses", "A framework of industry-specific standards"], "ans": 3}]}, {"title": "Questions 186-190 refer to the following e-mail, survey, and announcement.", "passage": "To: Undisclosed Recipients\nFrom: Brenda Pearson <bpearson@quinterolabs.com>\nDate: April 19\nSubject: Safety Survey\n\nAs you were absent from this morning's feedback session on improving safety in our laboratory, we would greatly appreciate your input through a brief online survey that has been set up for anyone who was not in attendance. Your insights are crucial for us to ensure we don't overlook any important aspects.\n\nPlease access the survey using the following link: www.q2qsurveys.com/QL705. When prompted for a password, use your unique 5-digit employee number followed by a hashtag (e.g. 12345#). Please note that the link will become inactive at precisely 4 P.M. on Friday, so make this task a priority.\n\nA few of our senior employees will compile the responses, and your feedback will be instrumental in shaping our safety policies and procedures. Many businesses in our field rely heavily on training sessions to improve safety. We hope this will not be necessary if we use effective policy changes and necessary equipment upgrades. We believe that gathering detailed feedback from our employees will help us achieve this goal.\n\nYour participation is essential for a safer work environment for everyone. Thank you in advance for taking the time to share your thoughts.\n\nSincerely,\n\nBrenda Pearson\nSite Supervisor, Quintero Labs\n\n---\n\nwww.q2qsurveys.com/QL705\n\nIn the box below, please share any concerns you may have regarding safety at Quintero Labs and make suggestions for improvements. We appreciate your assistance.\n\nDate: April 21          Name: Jeffrey Mendoza          Employee Number: 05891\n\nThe coat rack adjacent to the emergency exit is always congested with coats, and people frequently abandon bags and other personal items on the floor around it. This partially obstructs the emergency exit, making it a substantial fire hazard. If we had a secure and organized place to put our belongings, this issue would be eliminated. It is worth noting that I am not the only one in my department to feel this way; it is a regular topic of conversation when we meet at the water cooler in the hallway. I believe that such an improvement would not only enhance safety but also elevate employee morale.\nQuintero Labs Safety Improvement Plan\nPrepared by Anne Friedmann\n\nIn an effort to improve safety protocols at Quintero Labs, the following initiatives will be implemented over the coming months.\n\n1. Advanced fume hood systems will be installed at all workstations to ventilate hazardous fumes and vapors away from employees.\n\n2. Purpose-built storage lockers will be created in room 103, and all personal items, including coats and bags, should be stored there. This will help us to keep all entrances clear of obstacles.\n\n3. A new labeling system will be implemented to prevent the misuse of materials and to remind employees about proper handling procedures.\n\n4. An eye wash station will be added to the main laboratory to allow for the immediate rinsing of chemicals in the case of contamination.", "qs": [{"n": 186, "q": "In the e-mail, what is suggested about the survey?", "opts": ["It was also sent to employees by text.", "It is conducted on an annual basis.", "It has a strict submission deadline.", "It is protected by the password 12345#."], "ans": 2}, {"n": 187, "q": "According to Ms. Pearson, what does the company hope to avoid?", "opts": ["Having a high employee turnover", "Holding many training sessions", "Recording inaccurate information", "Spending too much on equipment"], "ans": 1}, {"n": 188, "q": "What is suggested about Mr. Mendoza?", "opts": ["He had difficulty accessing a survey form.", "He is a senior employee at Quintero Labs.", "He was not present at a feedback session on April 19.", "He has raised some safety concerns in the past."], "ans": 2}, {"n": 189, "q": "What does Mr. Mendoza indicate about his suggestion?", "opts": ["It will eliminate the need for bag checks.", "His previous workplace implemented a similar policy.", "It will not require any additional purchases.", "It has been echoed by many of his colleagues."], "ans": 3}, {"n": 190, "q": "What step outlined by Ms. Friedmann was brought up by Mr. Mendoza?", "opts": ["Step 1", "Step 2", "Step 3", "Step 4"], "ans": 1}]}, {"title": "Questions 191-195 refer to the following notice, Web page, and e-mail.", "passage": "Calling all theater fans!\n\nThe Stratford Drama Society is pleased to bring you a variety of interesting and entertaining stage shows this year. Our club will be performing a new show every month at the auditorium in the Stratford Community Center. From January to March, our performances will be plays written by our own talented members right here in Stratford, showcasing original and thought-provoking works that highlight local creativity. For the rest of the year, we will present classic works from playwrights of different time periods, including beloved titles by Shakespeare, Ibsen, and Chekhov. All plays will be directed by our founder. Visit www.stratforddrama.org to read more about the plays or to purchase tickets.\n\n---\n\nwww.stratforddrama.org/schedule\n\nWe hope to see a great turnout in support of live theater events in Stratford. Please find the schedule below and check back later, as more months will be added once the performances are confirmed.\n\nHere are the short descriptions for each performance:\n\nJanuary: The Enchanted Heart by Joan Wolfe\nA heartwarming tale of a family's love, loss, and redemption, set in a mystical village where hearts are mended in unexpected ways.\n\nFebruary: The Clocktower Mystery by Sandeep Sharma\nA thrilling mystery where secrets come to light in a small town, as a group of unlikely heroes races against time to solve the mystery of the old clocktower.\n\nMarch: The First Dance by Dale Aldrich\nA touching story of self-discovery and courage, following young Amy as she prepares for her first dance recital, overcoming obstacles and learning the true meaning of confidence.\n\nApril: The Merchant of Venice by William Shakespeare\nAn exploration of justice, mercy, and prejudice by a merchant, Antonio, who borrows money from the vengeful moneylender Shylock to help his friend, leading to dramatic consequences.\n\nMay: The Master Builder by Henrik Ibsen\nA psychological drama about ambition, fear, and the human desire for greatness, centered on architect Halvard Solness and his complex relationships with those around him as he confronts his own doubts and dreams.\n\nJune: To Be Determined\nTo: Elaine Hudson <ehudson@stratforddrama.org>\nFrom: Holly Tonkin <hollytonkin@clancymail.com>\nDate: February 26\nSubject: Event\n\nDear Ms. Hudson,\n\nI wanted to express how impressed I was by the recent Stratford Drama Society show. All the young cast members were very well-suited for their roles and performed them superbly, and your theatrical direction of the play was absolutely flawless. Because it was such a long play, I'm glad there was an intermission, as it gave me an opportunity to think about the narrative that had unfolded so far and discuss it with my companions. The storyline of the play was highly engaging and conveyed with clarity and emotion. I've always been interested in mysteries, and this show has inspired me to try my hand at writing my own mystery story. I think it will be a fulfilling way to make use of my spare time, and it is something I may not have considered had I not been so impressed with your play. I look forward to enjoying more of your shows this year.\n\nAll the best,\n\nHolly Tonkin", "qs": [{"n": 191, "q": "What is the purpose of the notice?", "opts": ["To give a review of a theater show", "To publicize some live performances", "To recruit members for a theater club", "To announce a change in a schedule"], "ans": 1}, {"n": 192, "q": "What is suggested about The Enchanted Heart?", "opts": ["It had a long intermission.", "Its tickets sold out very quickly.", "It is partly based on a news story.", "It was written by a Stratford resident."], "ans": 3}, {"n": 193, "q": "Which playwright most likely wrote a play about an individual's inner growth?", "opts": ["Joan Wolfe", "Sandeep Sharma", "Dale Aldrich", "William Shakespeare"], "ans": 2}, {"n": 194, "q": "What can be concluded about Ms. Hudson?", "opts": ["She met Ms. Tonkin after The Clocktower Mystery.", "She is highly interested in mystery novels.", "She played the lead character in a show.", "She founded the Stratford Drama Society."], "ans": 3}, {"n": 195, "q": "What does Ms. Tonkin indicate about the play she watched?", "opts": ["It motivated her to pursue a new pastime.", "It had a younger cast than she expected.", "Its narrative was somewhat confusing.", "It was similar to a book she had written."], "ans": 0}]}, {"title": "Questions 196-200 refer to the following article, review, and e-mail.", "passage": "Discover the Doughnuts!\nBy Mark Serrano\n\nSam's Doughnuts, celebrating its fifth anniversary, has been giving tours of its kitchen for the past three months now. This family-friendly experience allows visitors to see the magic behind their delicious creations, such as Chocolate Glaze and Berry Burst. Participants can watch every step in the doughnut-making process, from mixing the dough and cutting out the shapes to frying and passing the delicious rings of dough under a curtain of sweet glaze. Participants are also given free samples of the Original Sweet Glaze flavor at the end of the tour! When Sam's Doughnuts first opened for business, it sold only Original Sweet Glaze doughnuts, and they proved to be a huge hit, helping the establishment to build an excellent reputation by word of mouth.\n\nThere's much to enjoy at Sam's Doughnuts. On Tuesdays, unlimited coffee refills are served, and senior citizens receive discounts on Thursdays. And customers shouldn't miss out on trying Caramel Crunch, which has been outselling all other varieties by two to one since being introduced last month. Visit the business's Web site for further tour information.\n\nwww.businessrater.ca/samsdoughnuts\nPosted by Jill Bancroft, jbancroft@thornton.ca\nPosted on October 24\nRating: *****\n\nI recently visited Sam's Doughnuts and took their kitchen tour, which was fantastic. Our guide, the assistant manager of the shop, explained the entire doughnut-making process and answered all of our questions. After the tour, I relaxed in the dining area, which was packed with very satisfied customers of all ages. One of my favorite things about my visit was that I could ask a server for as many refills of coffee as I liked at no extra charge. For those who don't go on the tour, there is still a glass wall allowing a view of the doughnuts being fried. However, I wish there were tables right by the glass wall so I could sit and watch the process more comfortably instead of having to stand to see. Overall, it was a wonderful experience, and I highly recommend visiting for both the delicious doughnuts and the engaging kitchen tour.\nE-mail Message\n\nFrom: Sam's Doughnuts <albertk@samsdoughnuts.com>\nTo: Jill Bancroft <jbancroft@thornton.ca>\nDate: October 27\nSubject: Review\n\nDear Ms. Bancroft,\n\nThank you for your review of Sam's Doughnuts. We're pleased that you enjoyed the tour, and we hope you will visit again soon. Our head chef, Otis Frasier, is working with owner Sam Murphy to make some new recipes, and these will be introduced to our menu before the end of this year. Some of these are based on a survey conducted by our assistant manager, Melinda Laroche. As for your suggestion regarding our glass wall, we actually left that area free from tables purposely so that more people would be able to see the doughnut-making process during busy periods. Nevertheless, we appreciate your feedback.\n\nWarmest regards,\n\nAlbert Keaton\nManager, Sam's Doughnuts", "qs": [{"n": 196, "q": "What is indicated about Sam's Doughnuts?", "opts": ["It has been in business for five decades.", "It is a family-operated business.", "It moved to a new location three months ago.", "It has been marking a special occasion."], "ans": 3}, {"n": 197, "q": "According to the article, what has been the most popular doughnut recently?", "opts": ["Berry Burst", "Caramel Crunch", "Chocolate Glaze", "Original Sweet Glaze"], "ans": 1}, {"n": 198, "q": "What is suggested about Ms. Bancroft?", "opts": ["She had to leave a tour early.", "She is recognized as a senior citizen.", "She visited the business on a Tuesday.", "She took some doughnuts home with her."], "ans": 2}, {"n": 199, "q": "What is one purpose of the e-mail?", "opts": ["To provide the reasoning behind a decision", "To apologize that an item was unavailable", "To extend an invitation to join an upcoming tour", "To request some feedback on a recent experience"], "ans": 0}, {"n": 200, "q": "Who led the tour during Ms. Bancroft's visit?", "opts": ["Mr. Frasier", "Mr. Murphy", "Ms. Laroche", "Mr. Keaton"], "ans": 2}]}]}, "t3": {"p5": [{"n": 101, "en": "In its town center, Westland has the ______ stone wall of all structures in the region.", "opts": ["constant", "actual", "oldest", "simple"], "ans": 2}, {"n": 102, "en": "Ms. Morgan is trying to finalize the terms of the commercial building's lease before the owner ______ to raise the monthly rental fee.", "opts": ["decides", "to decide", "decided", "decide"], "ans": 0}, {"n": 103, "en": "We ______ Horizon Technologies value innovation, customer satisfaction, and a relentless pursuit of excellence.", "opts": ["onto", "at", "of", "to"], "ans": 1}, {"n": 104, "en": "On Friday morning, Mr. Lund plans ______ all applicants who passed the initial screening phase.", "opts": ["notifies", "notified", "notifying", "to notify"], "ans": 3}, {"n": 105, "en": "To ______ the lowest rates for your homeowners insurance, compare quotes from multiple providers.", "opts": ["affect", "secure", "reassure", "signify"], "ans": 1}, {"n": 106, "en": "All vacation requests must be submitted in writing to Ms. Blanche ______ five business days in advance.", "opts": ["at least", "instead of", "by means of", "so that"], "ans": 0}, {"n": 107, "en": "In case of a lost or damaged pass, we will deactivate it and issue ______ immediately.", "opts": ["other", "other one", "one another", "another"], "ans": 3}, {"n": 108, "en": "The customer service team is ______ most active during peak business hours, but they provide excellent support even outside these times.", "opts": ["typically", "gradually", "preferably", "barely"], "ans": 0}, {"n": 109, "en": "The architect used ______ solutions for incorporating sustainable materials into the building design of the new recreation center.", "opts": ["create", "creative", "creatively", "creation"], "ans": 1}, {"n": 110, "en": "______ the application is completed fully and correctly, the loan may be approved within three working days.", "opts": ["Contrary to", "As though", "Provided that", "To illustrate"], "ans": 2}, {"n": 111, "en": "______ half the passengers on the flight from Tokyo to Los Angeles prefer Japanese food, so the meal service is planned accordingly.", "opts": ["About", "Since", "Though", "As if"], "ans": 0}, {"n": 112, "en": "The Café Sunset, with gorgeous views of the sandy beach, has become ______ popular since its appearance in a movie.", "opts": ["significant", "significantly", "signifies", "significance"], "ans": 1}, {"n": 113, "en": "We should hold a meeting to invite the employees' ______ on the location of the future office expansion to ensure it meets the team's needs.", "opts": ["experience", "feedback", "funding", "access"], "ans": 1}, {"n": 114, "en": "A team leader must have the ability to stay calm and make a sound ______ under a lot of pressure.", "opts": ["decide", "decides", "decided", "decision"], "ans": 3}, {"n": 115, "en": "______ recruit is matched with a senior employee who will provide guidance for the 3-month probationary period.", "opts": ["Each", "All", "Some", "Most"], "ans": 0}, {"n": 116, "en": "Pro-TX athletic shoes can be recognized almost instantly from a distance on account of their ______ logo.", "opts": ["precise", "enthusiastic", "capable", "distinctive"], "ans": 3}, {"n": 117, "en": "Those interested in starting a free trial of our commercial video monitoring service are asked to contact our sales ______ after this demonstration.", "opts": ["represent", "representing", "representative", "representation"], "ans": 2}, {"n": 118, "en": "Now that we have streamlined the process, completing the project on time is not a ______ task.", "opts": ["complicated", "foreign", "moderate", "productive"], "ans": 0}, {"n": 119, "en": "When Mr. Anderson observed the heavy traffic, he opted to complete his commute by subway ______ bus.", "opts": ["because of", "such as", "rather than", "even though"], "ans": 1}, {"n": 120, "en": "______ leaves the office last is asked to make sure all computers and monitors are turned off.", "opts": ["Anyone", "Either", "Nobody", "Whoever"], "ans": 3}, {"n": 121, "en": "Carson International considerably reduced operating expenses last year by ______ its vehicles with leased ones.", "opts": ["replace", "replacing", "replaceable", "replacement"], "ans": 1}, {"n": 122, "en": "Foster Automotive will not honor the warranty of any vehicle whose engine has been repaired with ______ components.", "opts": ["use", "used", "using", "usage"], "ans": 1}, {"n": 123, "en": "The company strives to cater to the diverse ______ of its employees by offering various professional development opportunities and wellness programs.", "opts": ["applications", "actions", "evaluations", "interests"], "ans": 3}, {"n": 124, "en": "The owner of Granville Stadium has ______ agreed to let the Children's Baseball League use the site free of charge.", "opts": ["generous", "more generous", "generosity", "generously"], "ans": 3}, {"n": 125, "en": "The director of the Meadow Museum reminded patrons that a ______ of the admission fee goes toward sponsoring local art programs.", "opts": ["refund", "rate", "quality", "portion"], "ans": 3}, {"n": 126, "en": "The conference venue is already ______ booked, so we will need to look for alternative locations.", "opts": ["annually", "broadly", "completely", "kindly"], "ans": 2}, {"n": 127, "en": "New government legislation requires all frozen food labels to include a warning that ______ foods with artificial additives can be unhealthy.", "opts": ["consumer", "consumption", "consumes", "consuming"], "ans": 3}, {"n": 128, "en": "As explained in the company's brochure, all of the tax accountants at Bennett Consulting are ______ by the state.", "opts": ["certificates", "certifying", "certifies", "certified"], "ans": 3}, {"n": 129, "en": "While preparing for the safety inspection, please ensure that all boxes are removed from the hallways to ______ with fire regulations.", "opts": ["associate", "comply", "compare", "handle"], "ans": 1}, {"n": 130, "en": "Starlight Restaurant has decided to ______ Ms. Verma's proposal to purchase advertising space at half price for the first six months.", "opts": ["remind", "relate", "accept", "restore"], "ans": 2}], "p6": [{"title": "Questions 131-134 refer to the following e-mail.", "text": "To: Kate Chen <kate_chen@lefloremail.com>\nFrom: NH Sanitation <sanitation@newhaven.gov>\nDate: April 9\nSubject: Subscription Renewal\n\nDear Ms. Chen,\n\nThe garden waste collection subscription for 601 Hickory Lane will expire soon. When the subscription was originally set up, the automatic renewal option was not chosen. As such, (131)______ must renew the subscription before April 30 if you want to continue the service. (132)______. Click here to activate the renewal at your earliest convenience. Please note that a credit card is needed to pay the (133)______ fees.\n\n(134)______ a renewal not be requested, any grass clippings, leaves, and small branches in the collection bin will not be picked up. Residents can still dispose of garden waste themselves at the local waste facility.\n\nThank you,\n\nNew Haven Sanitation Department", "qs": [{"n": 131, "opts": ["yourself", "it", "you", "they"], "ans": 2}, {"n": 132, "opts": ["The service plan must be active to avoid a service disruption.", "We will contact successful applicants one week after this date.", "The collection day has changed from Monday to Thursday.", "We are sorry there was a delay in picking up the items."], "ans": 0}, {"n": 133, "opts": ["associates", "associating", "associate", "associated"], "ans": 3}, {"n": 134, "opts": ["Although", "Because", "Either", "Should"], "ans": 3}]}, {"title": "Questions 135-138 refer to the following advertisement.", "text": "Blossom Landscaping Services\n191 Shaw Road\nArmidale NSW 2350\nAustralia\n\nBlossom Landscaping Services can transform any yard into a beautiful outdoor space, making your (135)______ and vision a reality! Our team consists of ten highly experienced landscape gardeners, many of whom have worked in the industry for more than 20 years. They can plant flower beds and bushes, remove and control weeds, trim trees, and install irrigation systems and decorative water features. (136)______, ongoing lawn and garden maintenance services are available to keep everything looking great year-round. We have our own nursery to supply you with a wide range of common plants and flowers at an affordable price. (137)______. No matter what you need, we'll find a way to make it happen. And we always guarantee quality, (138)______ by our experience and attention to detail. Find out more at www.blossomlandscaping.au.", "qs": [{"n": 135, "opts": ["styled", "stylishly", "style", "stylish"], "ans": 2}, {"n": 136, "opts": ["And yet", "On the other hand", "Furthermore", "For instance"], "ans": 2}, {"n": 137, "opts": ["Plus, our partners can provide more unique items.", "Beginner gardeners will learn the basics of growing flowers.", "Moreover, the tree you selected provides ample shade.", "We appreciate your interest in our range of landscaping services."], "ans": 0}, {"n": 138, "opts": ["drives", "driven", "driving", "drive"], "ans": 1}]}, {"title": "Questions 139-142 refer to the following Web page.", "text": "https://www.occuseek.com\n\nOccuseek is a platform designed for individuals looking for an additional (139)______ of income through part-time, remote, or temporary employment. What began as a small local job board (140)______ into a top-rated Web site, trusted by thousands. Our site now boasts over 100,000 job vacancies, spanning a wide variety of fields from IT and customer services to engineering and construction. We diligently curate and update job listings daily to ensure a diverse array of options tailored to different industries and skill levels. Whether you are a recent university graduate or an experienced professional considering a change of career, we can cater to your requirements. Occuseek's (141)______ system makes it easy to use different search criteria across many databases. There is no cost for job seekers to join our platform, making it an accessible resource for all. (142)______. We look forward to supporting you on your professional journey.", "qs": [{"n": 139, "opts": ["trend", "purpose", "ratio", "source"], "ans": 3}, {"n": 140, "opts": ["developing", "has developed", "development", "develops"], "ans": 1}, {"n": 141, "opts": ["integrate", "integrates", "integration", "integrated"], "ans": 3}, {"n": 142, "opts": ["Different payment plans are available online.", "Your application for the position was successful.", "Please upload your résumé to complete your profile.", "So, sign up today to explore our offerings."], "ans": 3}]}, {"title": "Questions 143-146 refer to the following instructions.", "text": "Thank you for purchasing a Seacrest insulated bottle, the most convenient way to enjoy hot or cold drinks when on the go. Our bottles are manufactured from our patented ThermoFlex material, which is proven to maintain the temperature of liquid better than any other material on the market. Before using your bottle for the first time, wash it with warm, soapy water, and then (143)______ it to remove any residue. After cleaning, allow the bottle to air dry (144)______ before storing it with the lid off. This ensures that the bottle remains ventilated when not in use and stops the formation of mold. To maintain the optimal temperature of the contents when in use, preheat or prechill the bottle with hot or cold water for a few minutes. (145)______. Always take care when adding hot liquids to your bottle and use the handle to carry the bottle whenever it feels too hot. (146)______ prevent spillages, please keep the lid screwed on tightly.", "qs": [{"n": 143, "opts": ["wrap", "examine", "spread", "wash"], "ans": 3}, {"n": 144, "opts": ["completed", "completely", "complete", "completion"], "ans": 1}, {"n": 145, "opts": ["Otherwise, the moisture inside can create a bad odor.", "That's why the exterior has a scratch-resistant coating.", "Then, empty it before adding your desired beverage.", "To do so, label the bottle clearly with a marker."], "ans": 2}, {"n": 146, "opts": ["In order to", "In contrast to", "In addition to", "In response to"], "ans": 0}]}], "p7": [{"title": "Questions 147-148 refer to the following notice.", "passage": "Kessla Aquarium\n\nFor lost items, please inform a staff member at the information desk immediately. If the item is not found right away, you may be asked to provide your contact details so we can notify you once it is located. In the event that the item is found after you have already left the aquarium, we can arrange to have it delivered to you via courier service, depending on the nature and size of the item. Rest assured that all found items will be securely held by our security team for up to thirty days. During this time, you are welcome to contact us for updates or to claim your property. After this thirty-day period, any unclaimed items will be donated to a local charity. We greatly appreciate your cooperation in helping us maintain a well-organized environment for all visitors here at the Kessla Aquarium. For more information on our Lost & Found policy, please visit our Web site.", "qs": [{"n": 147, "q": "What does the notice suggest about some aquarium visitors?", "opts": ["They may be eligible to receive compensation for lost items.", "They might be responsible for a small fee to retrieve lost items.", "They may be required to provide a phone number.", "They can select their preferred courier for delivering lost items."], "ans": 2}, {"n": 148, "q": "What will happen to found items after thirty days?", "opts": ["They will be given to a charitable organization.", "They will be posted on the aquarium's Web site.", "They will be taken home by the security team.", "They will be delivered to a recycling center."], "ans": 0}]}, {"title": "Questions 149-150 refer to the following memo.", "passage": "To: All Irvine Station Staff\nFrom: Estelle McNeil, Station Manager\nRe: Bicycles\nDate: August 1\n\nPassengers have become increasingly frustrated with the difficulty in understanding the regulations regarding bringing bicycles on train journeys. To clarify, bicycles are allowed on our trains at no extra cost if the passenger holds a valid ticket. However, during peak times, those indicated in the schedule below, a reservation must be made for the bicycle. Failure to do so will result in the passenger being prohibited from boarding the train with the bicycle. I encourage you to thoroughly review the regulations yourselves to ensure that you may address any inquiries promptly and accurately.\n\nWeekdays: 6:30 A.M. to 9:00 A.M., 4:30 P.M. to 7:00 P.M.\nWeekends: 10:00 A.M. to 2:00 P.M., 4:00 P.M. to 6:00 P.M.", "qs": [{"n": 149, "q": "What is suggested in the memo?", "opts": ["Some passengers will receive refunds.", "The number of cyclists has increased.", "A policy has caused some confusion.", "A train station's hours have changed."], "ans": 2}, {"n": 150, "q": "What is indicated about trains departing at 7:00 A.M. on weekdays?", "opts": ["An advance booking must be made for bicycles.", "Passengers are not allowed to bring bicycles on board.", "Tickets are more expensive for people with bicycles.", "A special train car will be designated for bicycles."], "ans": 0}]}, {"title": "Questions 151-152 refer to the following text-message chain.", "passage": "Tabatha Kemp [3:07 P.M.]\nSharad, I stopped by Starlight Furniture. They have a decent selection of file cabinets, but not exactly the ones we need.\n\nSharad Pavagi [3:08 P.M.]\nWhat's the matter? Surely the type of cabinet we are looking for is pretty common.\n\nTabatha Kemp [3:09 P.M.]\nWell, they do carry two-drawer metal cabinets in the right size, and I had a look at some of them. The problem is that the drawers don't lock.\n\nSharad Pavagi [3:10 P.M.]\nThat's disappointing. We definitely need that feature, as they'll be used to hold our clients' confidential paperwork and our employee contracts.\n\nTabatha Kemp [3:11 P.M.]\nAlright. The salesperson at Starlight Furniture did mention that there are a few other furniture shops nearby. Should I see what types of cabinets they stock?\n\nSharad Pavagi [3:12 P.M.]\nYou've done enough. I'll see if I can find something online.", "qs": [{"n": 151, "q": "What is suggested about the file cabinets the writers need?", "opts": ["They will replace some older file cabinets.", "They will be placed in Mr. Pavagi's personal office.", "They need to have more than two drawers.", "They will securely store private information."], "ans": 3}, {"n": 152, "q": "At 3:12 P.M., what does Mr. Pavagi most likely mean when he writes, \"You've done enough\"?", "opts": ["He has decided that new file cabinets are not required.", "He does not require Ms. Kemp to visit any other businesses.", "He is satisfied with the file cabinets Ms. Kemp recommended.", "He will send Ms. Kemp details about shops in the neighborhood."], "ans": 1}]}, {"title": "Questions 153-154 refer to the following article.", "passage": "Small Business News\nBy Anna Scott\n\nAustin (May 12) — During a press conference held yesterday, Elliot Tech, a prominent player in the technology sector, officially announced the resignation of its CEO, Oscar Howland. The board of directors has appointed COO Alicia Cooper as the new CEO, effective November 1. Mr. Howland leaves behind a notable legacy of accomplishments. Under his leadership, Elliot Tech purchased Matias Software earlier this year, a high-profile acquisition that greatly expanded Elliot Tech's market presence. Mr. Howland also oversaw the successful launch of Docu-Pro, which has become the nation's leading file management software program, outselling its closest competitor by nearly 25% in market share. Furthermore, Elliot Tech was awarded the prestigious Ionia Prize for its significant contributions to community projects in Phoenix, the location of its headquarters.\n\nMs. Cooper is dedicated to upholding Elliot Tech's support model, which is characterized by assigning a dedicated data consultant to each client. No other company is using this personalized approach. With Ms. Cooper's promotion, the future of Elliot Tech is well positioned for continued innovation and growth.", "qs": [{"n": 153, "q": "What is one purpose of the article?", "opts": ["To highlight the achievements of a new CEO", "To report on an upcoming corporate acquisition", "To announce personnel changes at a company", "To introduce the launch of a technology firm"], "ans": 2}, {"n": 154, "q": "What is NOT indicated about Elliot Tech in the article?", "opts": ["It has a unique customer support model.", "It has a best-selling product.", "It was recognized for community involvement.", "It will relocate its headquarters."], "ans": 3}]}, {"title": "Questions 155-157 refer to the following advertisement.", "passage": "Marion Convention Center\n367 Park Street, Boston, MA 02199\nwww.marioncc.net · (617) 555-7962\n\nThe Marion Convention Center is the premier venue for business events and special celebrations. We have meeting rooms to suit parties of up to 500 people! Your participants will love the prime location of our site, which is within walking distance of a number of popular restaurants. We also offer a shuttle service from Logan International Airport, just a brief 20-minute ride away. For those who travel to our venue by personal vehicle, we provide on-site parking at very reasonable hourly rates.\n\nHigh-speed Wi-Fi is available throughout the facility. We can also set up microphones, a projector screen, a sound system, and more at no additional charge. E-mail Dennis Schultz at dschultz@marioncc.net to find out the details. Our friendly and experienced staff is ready to help your event run smoothly, so visit www.marioncc.net to reserve a room. We can provide a variety of decorations for special celebrations, although these do require an additional fee. And for those who book a room for any day from November 1 to November 30, we will provide complimentary tea and coffee for all of your guests as well as a platter of delicious sandwiches and cupcakes.\n\nFor unmatched professionalism, trust the Marion Convention Center!", "qs": [{"n": 155, "q": "What is true about the Marion Convention Center?", "opts": ["It has rooms for overnight guests.", "It has an on-site restaurant.", "It can accommodate large groups.", "It is a few minutes from the airport."], "ans": 2}, {"n": 156, "q": "Why should customers contact Mr. Schultz?", "opts": ["To arrange a deposit payment", "To make a room reservation", "To request a facility tour", "To inquire about equipment"], "ans": 3}, {"n": 157, "q": "What is being offered for free only in November?", "opts": ["Decorations", "A room upgrade", "Beverages", "On-site parking"], "ans": 2}]}, {"title": "Questions 158-160 refer to the following article.", "passage": "Lulu Cosmetics Acts to Reverse Customer Satisfaction Decline\n\nKELOWNA (2 July) — A recently conducted industry survey revealed that cosmetics company Lulu has encountered a notable decline in customer satisfaction ratings. Once highly respected for its quality and reliability, the company has experienced a downturn primarily due to inaccurate predictions of customer demand. — [1] —. Forecasting errors have led to significant inventory shortages and delays in fulfilling orders, adversely affecting the customer experience.\n\nIn response to this issue, the management team at Lulu plans to initiate a comprehensive strategy to address the underlying problems and restore the company's reputation. — [2] —. The top priority is investing in tools for advanced data analytics to better anticipate customers' needs and adequately prepare the correct amount of merchandise. “We are working to ensure that our world-class products are available to customers whenever they need them,” said Irene Labelle, a spokesperson for Lulu.\n\nLulu's supply chain infrastructure will be overhauled, a change that is hoped to improve the company's responsiveness. — [3] —. The company will strive for better collaboration with suppliers through more effective messaging to establish clear performance expectations. It may also expand the capacity of its warehouses. — [4] —. Through these efforts, the Lulu team is determined to regain customer trust and elevate its service standards once again, an essential goal in its highly competitive industry.", "qs": [{"n": 158, "q": "What has caused dissatisfaction among Lulu's customers?", "opts": ["A rise in the price of merchandise", "A lack of available stock", "A decline in the quality of goods", "An increase in errors in order lists"], "ans": 1}, {"n": 159, "q": "According to the article, how will Lulu try to enhance its relationships with suppliers?", "opts": ["By launching collaborative projects", "By outsourcing more production to suppliers", "By improving communication", "By establishing performance reviews"], "ans": 2}, {"n": 160, "q": "In which of the positions marked [1], [2], [3], and [4] does the following sentence best belong? “The enlargement of such storage spaces would help in handling future demand spikes.”", "opts": ["[1]", "[2]", "[3]", "[4]"], "ans": 3}]}, {"title": "Questions 161-163 refer to the following notice.", "passage": "NOTICE TO FULTON APARTMENTS TENANTS\n\nWe would like to announce a change to our parking policy, and this is effective immediately. The underground parking lots under Tower A and Tower B will now be restricted to tenant use only. Automated barrier gates will be installed, and electronic access cards that open the gates to permit entry will be issued (one per unit). We have decided to enact this policy due to the excessive use of the lots by visitors, resulting in difficulty for many of you in finding an empty spot.\n\nGuests may still park on the property, but they should use the above-ground lot east of Tower A, which will be clearly designated as \"Guest Parking.\" We ask that you leave these spots open for guests, unless you plan to park there for fifteen minutes or less. Delivery drivers will also be permitted to use this parking lot and will no longer be able to access the underground lots.\n\nTo retrieve your access card, stop by the property rental office anytime during business hours. You will need your license plate number, which will be recorded for our security team's records, and a photo ID. As a reminder, if you notice any malfunctioning lights in the underground lot — or any other things that need to be fixed — please call Jim at 555-3119.", "qs": [{"n": 161, "q": "According to the notice, what is the reason for the change?", "opts": ["A parking area is overcrowded.", "The number of tenants has increased.", "An underground lot is newly opened.", "The fees for public parking have risen."], "ans": 0}, {"n": 162, "q": "What is mentioned about visitors to Fulton Apartments?", "opts": ["They can park underground for fifteen minutes or less.", "They should use a designated parking area.", "They can get a temporary parking pass.", "They must report their license plate numbers."], "ans": 1}, {"n": 163, "q": "Why should people call the phone number provided?", "opts": ["To report a maintenance issue", "To get a parking pass issued", "To inquire about a new policy", "To request a replacement card"], "ans": 0}]}, {"title": "Questions 164-167 refer to the following memo.", "passage": "To: All Staff\nFrom: Marilyn Dodson, Office Manager, Vista Inc.\nRe: Stowell Enterprises\nDate: May 8\n\nVista Inc. is poised for a significant transformation now that the business deal with Stowell Enterprises is moving forward. The founders of both companies officially signed an agreement yesterday finalizing the joining together of the two corporations. The next phase of this transitional period involves determining the most effective strategy for utilizing our collective resources. Therefore, from May 14 to 18, an independent consultant named Scott Pierce will visit our branch.\n\nMr. Pierce has been tasked with conducting a comprehensive analysis of each department's functions and processes. As part of his assignment, Mr. Pierce will engage in interviews with all managers and a majority of our long-term employees. The precise schedule for these interviews has not been fully arranged, as Mr. Pierce has not yet specified the individuals he requires to meet. Nevertheless, I will ensure that each of you receives a detailed timetable via e-mail sometime next week. Furthermore, the report generated by Mr. Pierce regarding our branch's performance and processes will be made available in early June, and I will post it on the employee section of the company's Web site.\n\nI would like to extend my sincere appreciation in advance for your cooperation. I am confident that this transition will mark the beginning of an unprecedented period of success for our business!", "qs": [{"n": 164, "q": "What is indicated about Vista Inc.?", "opts": ["It received low customer ratings.", "Its main competitor is Stowell Enterprises.", "It will merge with another business.", "It has plans to launch a new product."], "ans": 2}, {"n": 165, "q": "What will Mr. Pierce do during his visit?", "opts": ["Give a presentation on a product", "Assess the company's operations", "Negotiate the terms of a contract", "Install some new equipment"], "ans": 1}, {"n": 166, "q": "What does Ms. Dodson plan to do next week?", "opts": ["Confirm a schedule", "Post a report online", "Conduct an interview", "Take a business trip"], "ans": 0}, {"n": 167, "q": "The word \"extend\" in paragraph 3, line 1, is closest in meaning to", "opts": ["enlarge", "reach", "express", "prolong"], "ans": 2}]}, {"title": "Questions 168-171 refer to the following advertisement.", "passage": "Oakbrook Swim Club is the area's largest swimming facility, with three pools catering to various ages and activities, including one heated pool. — [1] —. We're open from the early morning to late in the evening, 5:00 A.M. to 9:30 P.M., so you can enjoy swimming at our facility whenever it fits your schedule.\n\nDon't miss our special promotion in March and April! — [2] —. During this promotional period, when you purchase a package of swimming lessons, you'll receive a voucher to use in our on-site swim shop. There you can find a wide range of high-quality gear to complement your swimming needs. — [3] —.\n\nWe offer two different packages of swimming lessons, so you may select the package that is right for you. Purchase a package of 12 lessons for $10 each and receive a $15 voucher. Purchase a package of 20 lessons for $9 each and receive a $30 voucher.\n\nThis offer is available to both new and existing members, and there is no limit to the number of packages you can purchase. The packages are valid for one year, so the lessons do not need to be used during the promotional months. — [4] —. Voucher(s) can be picked up at the reception desk during your next visit if the online method is used.\n\nDon't miss this opportunity to enhance your swimming experience for a great price at Oakbrook Swim Club!", "qs": [{"n": 168, "q": "What benefit of Oakbrook Swim Club does the advertisement mention?", "opts": ["Its experienced instructors", "Its accessible location", "Its convenient hours", "Its outdoor pools"], "ans": 2}, {"n": 169, "q": "What voucher value will customers be given for a smaller package?", "opts": ["$9.00", "$10.00", "$15.00", "$30.00"], "ans": 2}, {"n": 170, "q": "What is indicated about the promotion?", "opts": ["The lessons must be used in March or April.", "Customers can take advantage of it more than once.", "It is aimed at attracting new members to the swim club.", "Purchases made in the upcoming year are eligible."], "ans": 1}, {"n": 171, "q": "In which of the positions marked [1], [2], [3], and [4] does the following sentence best belong? \"You can make your purchase in person or on our Web site.\"", "opts": ["[1]", "[2]", "[3]", "[4]"], "ans": 3}]}, {"title": "Questions 172-175 refer to the following online chat discussion.", "passage": "Carla Ramos [11:17 A.M.]  Ashley and Kenneth, there are three new employees starting in the accounting department on Monday, but there aren't any spare desks for them. Any ideas for addressing this issue?\nAshley Jenkins [11:18 A.M.]  They're going to be working on the 5th floor, right?\nCarla Ramos [11:19 A.M.]  Eventually, yes. But we need a temporary place for them until the crew finishes renovating that floor. It was supposed to be completed by this weekend, but the contractor just informed me that they need a few more days.\nKenneth Evans [11:21 A.M.]  We've already had to relocate the rest of the 5th-floor workers to other floors.\nAshley Jenkins [11:22 A.M.]  How about having the new employees work in the conference room for a few days? The table is large enough to set up a few computers.\nCarla Ramos [11:23 A.M.]  There's a sales training session. It starts on Monday morning and lasts for three days.\nKenneth Evans [11:24 A.M.]  I remember hearing about that. Is Deborah Vega the person leading the session?\nCarla Ramos [11:25 A.M.]  Yes, that's right.\nAshley Jenkins [11:26 A.M.]  Perhaps she wouldn't mind if we booked an off-site venue for the training instead. I'll reach out to her to see if that is feasible.\nCarla Ramos [11:27 A.M.]  Thanks for taking the initiative on that, Ashley. I appreciate it.", "qs": [{"n": 172, "q": "What are the writers mainly discussing?", "opts": ["Reviewing job performance", "Recruiting new employees", "Organizing workstations", "Ordering office furniture"], "ans": 2}, {"n": 173, "q": "What is indicated about the writers' company?", "opts": ["It will relocate to another building.", "It specializes in accounting services.", "It is closed on the weekend.", "It is undergoing renovations."], "ans": 3}, {"n": 174, "q": "At 11:23 A.M., what does Ms. Ramos most likely mean when she writes, “There's a sales training session”?", "opts": ["She knows that a room is not available.", "She recommends a learning opportunity.", "She is too busy to assist with a request.", "She expects to be absent from the office."], "ans": 0}, {"n": 175, "q": "What does Ms. Jenkins offer to do?", "opts": ["Contact a colleague", "Set up a conference room", "Book a venue", "Cancel a meeting"], "ans": 0}]}, {"title": "Questions 176-180 refer to the following e-mail and invitation.", "passage": "E-mail Message\n\nTo: Gregory Cole <cole.gregory@finchamuni.edu>\nFrom: Susan Palmier <s_palmier@ezmailinbox.com>\nDate: October 4\nSubject: Eminence Awards\n\nDear Mr. Cole,\n\nThe highly anticipated Eminence Awards are fast approaching, and this year's competition promises to be particularly intense. We are in for a thrilling evening of recognition and achievement. I want to thank you once again for agreeing to present the award for the field of chemistry at the October 20 event. The presenters are expected to arrive at the Durham Hotel no later than 6:30 P.M., where we will convene in the Canary Room, located adjacent to the main ballroom, the venue for the ceremony. Both rooms will be marked on the map of the hotel, which I will send to you along with a voucher for the underground parking lot and the lineup of presenters.\n\nDinner will be served at 7:00 P.M., and you will sit at the presenters' table and join in the meal. I will also be at that table, and I'll inform you of when you need to go on stage. The awards ceremony will begin at 7:30 P.M. and last approximately ninety minutes. Please note that you should come dressed in a suit with a dress shirt and tie. Should you have any inquiries or require further clarification, feel free to reach out to me via e-mail.\n\nSincerely,\n\nSusan Palmier\n\n\nYou are cordially invited to\nThe 16th Annual Eminence Awards\nOctober 20 at the Durham Hotel\nDoors open at 6:00 P.M. | Dinner at 7:00 P.M. | Awards ceremony at 7:30 P.M.\n\nThe Eminence Awards is a prestigious annual event that honors outstanding achievements in chemistry, biology, and physics. Host Carl Jackson, one of last year's recipients, will lead the ceremony along with support from presenters for individual awards. Right after the ceremony concludes, all award winners and presenters will gather together in the main foyer, where a professional photographer will take a picture to commemorate the occasion. To confirm your attendance at this year's event, please RSVP by e-mail at organizer@eminence.org at your earliest convenience.", "qs": [{"n": 176, "q": "What is the purpose of the e-mail?", "opts": ["To give instructions to a presenter", "To congratulate an award nominee", "To announce a change in a schedule", "To accept an invitation to an event"], "ans": 0}, {"n": 177, "q": "What is NOT something that Ms. Palmier will send to Mr. Cole?", "opts": ["A meal voucher", "A parking pass", "A venue map", "A list of presenters"], "ans": 0}, {"n": 178, "q": "What does Ms. Palmier remind Mr. Cole to do?", "opts": ["Send his presentation slides", "Confirm his attendance", "Bring his invitation", "Wear formal attire"], "ans": 3}, {"n": 179, "q": "When most likely will the group photo be taken?", "opts": ["At 6:30 P.M.", "At 7:00 P.M.", "At 7:30 P.M.", "At 9:00 P.M."], "ans": 3}, {"n": 180, "q": "Who most likely is Mr. Jackson?", "opts": ["An event organizer", "A venue owner", "A leading scientist", "An award-winning author"], "ans": 2}]}, {"title": "Questions 181-185 refer to the following e-mail and review.", "passage": "E-mail Message\n\nTo: Teresa Durante <t.durante@yorba1.com>\nFrom: Norcross Health <cservice@norcrosshealth.com>\nDate: January 13\nSubject: Order #75834\n\nDear Ms. Durante,\n\nThank you for your purchase of the R-15 motorized treadmill from Norcross Health. We have successfully processed your payment, and the delivery is scheduled for January 20. Please note that minimal assembly is required for this item, and all parts and tools required for assembly are included in the box.\n\nRegarding your previous inquiry, we do offer additional protection for our products. Please reply directly to this message, keeping the order number in the subject line, if you would like to change from the Standard 1-year warranty to our Premium 5-year warranty. This can be done for a one-time payment of $49.95. This covers all parts and labor for mechanical and electrical repairs, and filing a claim is quick and easy through our Web site.\n\nIn addition, if you post a review of the treadmill on our Web site, you will be entered into our prize drawing for a six-month supply of protein powder. Simply complete your review by January 31, and you will be entered automatically. We will contact you at this e-mail address if you are the winner.\n\nSincerely,\n\nAnita Wright\nCustomer Service Representative, Norcross Health\n\nwww.norcrosshealth.com/reviews/treadmills/r-15\n\nHOME    TREADMILLS    EXERCISE BIKES    REVIEWS    CONTACT\n\nHome >> Reviews >> Treadmills >> R-15\n\nPosted January 22 by Teresa Durante\n\nI received my R-15 earlier this week, one day earlier than scheduled, and overall I am highly satisfied with the device and would enthusiastically recommend it to others. Its setup instructions are clear, and it has a sturdy design. I wanted the R-15 as a replacement for an earlier model that I bought about five years ago. This one is vastly superior to its predecessor, as it has more speed settings and can track your progress in time, distance, or calories burned. If I had one critique about this device, it would be that it takes up a great deal of space. The railings along the side are fixed and cannot be removed, so you cannot fold it up for storage.", "qs": [{"n": 181, "q": "Why might Ms. Durante e-mail Ms. Wright?", "opts": ["To pay an outstanding balance", "To request repairs to a product", "To confirm a delivery address", "To extend a product warranty"], "ans": 3}, {"n": 182, "q": "What is Ms. Durante eligible to receive?", "opts": ["An admission ticket for a special event", "A catalog of Norcross Health's goods", "A chance to win a dietary supplement", "A discount coupon for a future purchase"], "ans": 3}, {"n": 183, "q": "When did Ms. Durante receive the treadmill?", "opts": ["On January 13", "On January 19", "On January 20", "On January 21"], "ans": 1}, {"n": 184, "q": "What is suggested about Ms. Durante?", "opts": ["She found out about the R-15 through a friend.", "She uses the R-15 for her workouts every day.", "She requested expedited shipping for her order.", "She has purchased a Norcross Health product before."], "ans": 3}, {"n": 185, "q": "In the review, the word \"fixed\" in paragraph 1, line 6, is closest in meaning to", "opts": ["located", "determined", "repaired", "fastened"], "ans": 3}]}, {"title": "Questions 186-190 refer to the following article, schedule, and e-mail.", "passage": "Madisonville Business Spotlight\n\nMarch 17 — Eco-Linens, a new local business specializing in the rental of high-quality linens, has officially opened in Madisonville. Eco-Linens supplies tablecloths, seat covers, napkins, and more for special events such as family gatherings and corporate banquets. It offers a selection of elegant black or white linens in cotton, linen, and satin, as well as a wide range of colors in durable polyester.\n\nThe items are cleaned and ironed using eco-friendly methods. Deliveries, made in an electric vehicle charged with solar-generated power, are available every day of the week.\n\n\"Our goal is to provide exceptional service and quality while maintaining a commitment to the environment,\" says owner and long-time Madisonville resident Lisa Odell. \"We are honored to be a part of special occasions here in Madisonville.\"\n\nEco-Linens: Schedule of Assigned Tasks\nDate: April 29\n\nClient | Venue | Item Type(s) | Order # | Prepared By\nCandice Wiggins | Aurora Building | Tablecloths, napkins | 0211 | Anthony Barrett\nLongview Accounting | Kenbridge Hotel | Food station covers, napkins, tablecloths | 0213 | Soo-jin Kim\nKey Realty | Lowery Hall | Tablecloths, chair covers, bows | 0224 | Bruno Almeida\nAlan Hart | 1404 Sampson Street (residence) | Tablecloths, napkins, bows | 0227 | Lisa Odell\nTo: Eco-Linens <contact@eco-linens.com>\nFrom: Heather Shulman <hshulman@topmail1.com>\nDate: May 2\nSubject: Thank you!\n\nTo Whom It May Concern:\n\nI am writing to express my sincere appreciation for your outstanding service at Longview Accounting's recent employee appreciation dinner. I mistakenly ordered the incorrect size of the forest green tablecloths for our recent event, which I did not realize until we started decorating the venue. Fortunately, when I called your company, the receptionist checked the inventory immediately and found the items we needed. Thanks to the prompt dispatch of the correct size in the same color, we were still able to have everything ready on time. I was particularly impressed by your delivery driver's attentiveness, as he made sure that the new items were the right size before departing. I will certainly be utilizing your services for future events. Thank you once again for your exceptional service.\n\nWarmest regards,\n\nHeather Shulman", "qs": [{"n": 186, "q": "What does the article indicate about Eco-Linens?", "opts": ["Its delivery vehicle uses a renewable energy source.", "Its products are made from recycled materials.", "It is the first company of its kind in Madisonville.", "It is a family-owned-and-operated business."], "ans": 0}, {"n": 187, "q": "According to the schedule, who will prepare some linens for seats?", "opts": ["Mr. Barrett", "Ms. Kim", "Mr. Almeida", "Ms. Odell"], "ans": 2}, {"n": 188, "q": "Where did Ms. Shulman use Eco-Linens's services?", "opts": ["At the Aurora Building", "At the Kenbridge Hotel", "At Lowery Hall", "At a private residence"], "ans": 1}, {"n": 189, "q": "What is probably true about the tablecloths Ms. Shulman used?", "opts": ["They were damaged in transit.", "They were not the originally ordered color.", "They were made of polyester.", "They were used at a recruitment event."], "ans": 2}, {"n": 190, "q": "In the e-mail, what is indicated about the Eco-Linens driver?", "opts": ["He noticed an error in Ms. Shulman's order.", "He checked an inventory after speaking to Ms. Shulman.", "He had difficulty locating the venue at first.", "He stayed to check that the replacements were correct."], "ans": 3}]}, {"title": "Questions 191-195 refer to the following letter, Web page, and e-mail.", "passage": "Beaumont Small Business Association\nFarland Building, #319\n366 Veltri Avenue\nBeaumont, TX 77725\n\nApril 8\n\nStanley Warren\nWarren Health Foods\n4302 Dayle Drive\nBeaumont, TX 77708\n\nDear Mr. Warren,\n\nThank you for renewing your Beaumont Small Business Association (BSBA) membership for another year. Your annual payment of $125.00 has been processed and will appear on your credit card statement as \"Beaumont SBA\". You will continue to have access to the members-only section of our Web site, as well as all our BSBA events. Please ensure that your listing on our business directory is up to date.\n\nOur annual networking dinner is taking place on June 13 at 7:00 P.M. at the Hanover Convention Center. Please RSVP by e-mailing me at jfrancis@beaumontsba.org. When doing so, you should indicate what type of business you operate.\n\nWarmest regards,\n\nJennifer Francis\nBSBA Membership Services\n\nbeaumontsba.org/directory/warren_health_foods\n\nBusiness: Warren Health Foods    Owner: Stanley Warren    Address: 4302 Dayle Drive\n\nEstablished five years ago, Warren Health Foods specializes in healthy groceries, organic snacks, premium vitamin supplements, herbal teas, and more. Although consumers are looking for ways to improve their health through diet, health-focused items only account for around ten percent of merchandise in supermarkets. Warren Health Foods is here to bridge that gap. We pride ourselves on sourcing only products of the highest quality, and our knowledgeable staff is dedicated to offering personalized advice to help customers achieve their wellness goals.\nE-mail Message\n\nTo: Sandra Schmidt <sschmidt@jupitermail.com>\nFrom: Stanley Warren <stanley@warrenhf.com>\nDate: June 14\nSubject: Conversation follow-up\n\nDear Ms. Schmidt,\n\nIt was a pleasure meeting you at yesterday's BSBA dinner. I'm glad that the organizers seated people from the same industry together at the same table. It was interesting to hear how your business in Asheboro is performing compared to the one you have here in Beaumont, though I'm sorry to hear that you are struggling. My assistant manager, Angelina Salazar, is planning to move back to her hometown of Asheboro soon, and I believe that she would be an excellent addition to your team. I have been impressed with her hard work and excellent organizational skills at my own store. If you are interested in speaking to her further, please let me know, and I can share her contact information with you.\n\nAll the best,\n\nStanley Warren", "qs": [{"n": 191, "q": "What does Ms. Francis indicate about the BSBA?", "opts": ["It has recently updated its business directory.", "It organizes several events throughout the year.", "It charges a monthly fee for membership.", "It restricts access to some of its online features."], "ans": 3}, {"n": 192, "q": "On the Web page, the phrase \"account for\" in paragraph 1, line 3, is closest in meaning to", "opts": ["display", "calculate", "represent", "use"], "ans": 2}, {"n": 193, "q": "What is suggested about Mr. Warren?", "opts": ["He opened his business three years ago.", "He sent an e-mail to Ms. Francis.", "He wants to buy Ms. Schmidt's business.", "He makes his own herbal teas."], "ans": 1}, {"n": 194, "q": "What is most likely true about Ms. Schmidt?", "opts": ["She works in the health food industry.", "She gave a speech at a networking event.", "She offered Mr. Warren a job.", "She is a new member of the BSBA."], "ans": 0}, {"n": 195, "q": "What is the purpose of the e-mail?", "opts": ["To apply for a job opening", "To recommend a colleague", "To gather details about a business", "To offer a professional service"], "ans": 1}]}, {"title": "Questions 196-200 refer to the following e-mails.", "passage": "E-mail Message\n\nTo: Luna Printing <orders@lunaprinting.com>\nFrom: Evelyn Draper <edraper@libertyind.com>\nDate: July 11, 1:49 P.M.\nSubject: RE: Order #06858 Receipt\nAttachment: liberty_logo\n\nDear Mr. Hale,\n\nI've received the receipt for our recent order, but I'm wondering about the confirmation date. I provided a file containing the design yesterday. Unfortunately, it was not the correct one. I e-mailed an updated file earlier this morning, and that is the one I confirmed. I've attached it here again to make sure that this is the design being used. We've ordered one T-shirt for each of our employees to wear at an upcoming retreat, so it is crucial that everything is correct. Could you please double-check the design prior to printing?\n\nThank you,\n\nEvelyn Draper", "qs": [{"n": 196, "q": "What is indicated about Luna Printing?", "opts": ["The color of its items may vary depending on the size.", "Refunds are issued for faulty items only.", "Customers must provide confirmation of the order.", "Merchandise can be exchanged but not refunded."], "ans": 2}, {"n": 197, "q": "What is suggested about the Cosgrove Building?", "opts": ["It is located within five miles of the Melrose Building.", "It has recently become the Liberty Industries office.", "It has more stories than the Melrose Building.", "It is the former location of Luna Printing's shop."], "ans": 0}, {"n": 198, "q": "What is the purpose of the second e-mail?", "opts": ["To check that a change has been made", "To add more items to an order", "To complain about a pricing error", "To confirm the date of delivery"], "ans": 0}, {"n": 199, "q": "What problem does Ms. Draper mention?", "opts": ["A business address was not correct.", "A design file was not properly saved.", "A size was smaller than expected.", "An incorrect design was sent."], "ans": 3}, {"n": 200, "q": "What is true about Liberty Industries?", "opts": ["It has recently updated its logo.", "It has sixty-five employees.", "It changed the date of a retreat.", "It regularly uses Luna Printing."], "ans": 1}]}]}};
